(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,830223,e=>{"use strict";let o=new Set,a=[{id:"ko-a1-greetings-001",level:"A1",deck:"greetings",en:"Hello",ko:"안녕하세요",roman:"annyeonghaseyo",exampleKo:"안녕하세요, 만나서 반가워요.",exampleEn:"Hello, nice to meet you.",note:"The standard polite greeting — works any time of day."},{id:"ko-a1-greetings-002",level:"A1",deck:"greetings",en:"Goodbye (to someone leaving)",ko:"안녕히 가세요",roman:"annyeonghi gaseyo",exampleKo:"안녕히 가세요, 또 만나요.",exampleEn:"Goodbye, see you again.",note:"Say this to the person who is leaving while you stay."},{id:"ko-a1-greetings-003",level:"A1",deck:"greetings",en:"Goodbye (to someone staying)",ko:"안녕히 계세요",roman:"annyeonghi gyeseyo",exampleKo:"안녕히 계세요, 내일 봬요.",exampleEn:"Goodbye, see you tomorrow.",note:"Say this when you are the one leaving and they stay."},{id:"ko-a1-greetings-004",level:"A1",deck:"greetings",en:"Thank you",ko:"감사합니다",roman:"gamsahamnida",exampleKo:"도와주셔서 감사합니다.",exampleEn:"Thank you for your help.",note:"Polite, formal thanks — safe in almost any situation."},{id:"ko-a1-greetings-005",level:"A1",deck:"greetings",en:"Thanks",ko:"고맙습니다",roman:"gomapseumnida",exampleKo:"정말 고맙습니다.",exampleEn:"Thank you so much.",note:"Also polite; a touch warmer and more native than 감사합니다."},{id:"ko-a1-greetings-006",level:"A1",deck:"greetings",en:"I'm sorry",ko:"죄송합니다",roman:"joesonghamnida",exampleKo:"늦어서 죄송합니다.",exampleEn:"I'm sorry for being late.",note:"Formal apology. Use 미안해요 with close friends."},{id:"ko-a1-greetings-007",level:"A1",deck:"greetings",en:"It's okay / It's fine",ko:"괜찮아요",roman:"gwaenchanayo",exampleKo:"괜찮아요, 신경 쓰지 마세요.",exampleEn:"It's okay, don't worry about it.",note:"Versatile: accepts apologies, declines offers, says you're fine."},{id:"ko-a1-greetings-008",level:"A1",deck:"greetings",en:"Yes",ko:"네",roman:"ne",exampleKo:"네, 맞아요.",exampleEn:"Yes, that's right.",note:"Standard polite 'yes'. 예 (ye) is a bit more formal."},{id:"ko-a1-greetings-009",level:"A1",deck:"greetings",en:"No",ko:"아니요",roman:"aniyo",exampleKo:"아니요, 괜찮아요.",exampleEn:"No, I'm fine.",note:"Polite 'no'. Often softened with 괜찮아요 to stay friendly."},{id:"ko-a1-greetings-010",level:"A1",deck:"greetings",en:"Excuse me",ko:"실례합니다",roman:"sillyehamnida",exampleKo:"실례합니다, 길 좀 묻겠습니다.",exampleEn:"Excuse me, may I ask for directions?",note:"Use to get attention politely or before interrupting."},{id:"ko-a1-greetings-011",level:"A1",deck:"greetings",en:"Nice to meet you",ko:"만나서 반갑습니다",roman:"mannaseo bangapseumnida",exampleKo:"만나서 반갑습니다. 저는 민수예요.",exampleEn:"Nice to meet you. I'm Minsu.",note:"Standard first-meeting line. 반가워요 is the softer casual form."},{id:"ko-a1-greetings-012",level:"A1",deck:"greetings",en:"How have you been?",ko:"잘 지내셨어요?",roman:"jal jinaesyeosseoyo?",exampleKo:"오랜만이에요. 잘 지내셨어요?",exampleEn:"Long time no see. How have you been?",note:"Polite catch-up greeting for someone you haven't seen in a while."},{id:"ko-a1-self-intro-001",level:"A1",deck:"self-intro",en:"I am ~ (My name is ~)",ko:"저는 ~예요",roman:"jeoneun ~yeyo",exampleKo:"저는 사라예요.",exampleEn:"I'm Sarah.",note:"Use 예요 after a vowel, 이에요 after a consonant. 저는 = 'as for me'."},{id:"ko-a1-self-intro-002",level:"A1",deck:"self-intro",en:"My name is ~",ko:"제 이름은 ~이에요",roman:"je ireumeun ~ieyo",exampleKo:"제 이름은 민준이에요.",exampleEn:"My name is Minjun.",note:"제 이름은 = 'my name'. A more explicit way to give your name."},{id:"ko-a1-self-intro-003",level:"A1",deck:"self-intro",en:"What is your name?",ko:"이름이 뭐예요?",roman:"ireumi mwoyeyo?",exampleKo:"안녕하세요, 이름이 뭐예요?",exampleEn:"Hello, what's your name?",note:"Casual-polite. Use 성함이 어떻게 되세요? to be extra formal."},{id:"ko-a1-self-intro-004",level:"A1",deck:"self-intro",en:"Where are you from?",ko:"어디에서 왔어요?",roman:"eodieseo wasseoyo?",exampleKo:"어디에서 왔어요? 저는 캐나다에서 왔어요.",exampleEn:"Where are you from? I'm from Canada.",note:"Literally 'where did you come from?'. A standard get-to-know-you line."},{id:"ko-a1-self-intro-005",level:"A1",deck:"self-intro",en:"I'm from ~",ko:"저는 ~에서 왔어요",roman:"jeoneun ~eseo wasseoyo",exampleKo:"저는 미국에서 왔어요.",exampleEn:"I'm from the US.",note:"Put the country before 에서. 에서 marks the place of origin."},{id:"ko-a1-self-intro-006",level:"A1",deck:"self-intro",en:"I am a student",ko:"저는 학생이에요",roman:"jeoneun haksaengieyo",exampleKo:"저는 대학교 학생이에요.",exampleEn:"I'm a university student.",note:"학생 = student. 이에요 follows because 학생 ends in a consonant."},{id:"ko-a1-self-intro-007",level:"A1",deck:"self-intro",en:"What do you do (for work)?",ko:"무슨 일 하세요?",roman:"museun il haseyo?",exampleKo:"실례지만, 무슨 일 하세요?",exampleEn:"Excuse me, what do you do for work?",note:"Literally 'what work do you do?'. Polite way to ask someone's job."},{id:"ko-a1-self-intro-008",level:"A1",deck:"self-intro",en:"I am an office worker",ko:"저는 회사원이에요",roman:"jeoneun hoesawonieyo",exampleKo:"저는 회사원이에요. 서울에서 일해요.",exampleEn:"I'm an office worker. I work in Seoul.",note:"회사원 = company employee, a very common answer about one's job."},{id:"ko-a1-self-intro-009",level:"A1",deck:"self-intro",en:"Nice to meet you (set phrase)",ko:"잘 부탁드려요",roman:"jal butakdeuryeoyo",exampleKo:"앞으로 잘 부탁드려요.",exampleEn:"I look forward to working with you.",note:"Set phrase to close an introduction. No direct English equivalent."},{id:"ko-a1-self-intro-010",level:"A1",deck:"self-intro",en:"How old are you?",ko:"나이가 어떻게 되세요?",roman:"naiga eotteoke doeseyo?",exampleKo:"나이가 어떻게 되세요? 저는 스물다섯 살이에요.",exampleEn:"How old are you? I'm twenty-five.",note:"Polite way to ask age. Age matters for choosing the right speech level."},{id:"ko-a1-self-intro-011",level:"A1",deck:"self-intro",en:"I live in ~",ko:"저는 ~에 살아요",roman:"jeoneun ~e sarayo",exampleKo:"저는 서울에 살아요.",exampleEn:"I live in Seoul.",note:"에 marks the place where you live (location, not direction)."},{id:"ko-a1-self-intro-012",level:"A1",deck:"self-intro",en:"Please speak comfortably (casually) to me",ko:"말씀 편하게 하세요",roman:"malsseum pyeonhage haseyo",exampleKo:"제가 더 어려요. 말씀 편하게 하세요.",exampleEn:"I'm younger. Please feel free to speak casually to me.",note:"Polite offer to let an older person drop formal speech with you."},{id:"ko-a1-numbers-001",level:"A1",deck:"numbers",en:"one (native)",ko:"하나",roman:"hana",exampleKo:"커피 하나 주세요.",exampleEn:"One coffee, please.",note:"Native Korean number. Used for counting things, age, and hours."},{id:"ko-a1-numbers-002",level:"A1",deck:"numbers",en:"two (native)",ko:"둘",roman:"dul",exampleKo:"사과 둘이요.",exampleEn:"Two apples.",note:"Becomes 두 before a counter: 두 개 (two items), 두 명 (two people)."},{id:"ko-a1-numbers-003",level:"A1",deck:"numbers",en:"three (native)",ko:"셋",roman:"set",exampleKo:"셋이 함께 가요.",exampleEn:"The three of us go together.",note:"Becomes 세 before a counter: 세 잔 (three cups/glasses)."},{id:"ko-a1-numbers-004",level:"A1",deck:"numbers",en:"four (native)",ko:"넷",roman:"net",exampleKo:"의자가 넷 있어요.",exampleEn:"There are four chairs.",note:"Becomes 네 before a counter: 네 개 (four items)."},{id:"ko-a1-numbers-005",level:"A1",deck:"numbers",en:"five (native)",ko:"다섯",roman:"daseot",exampleKo:"다섯 명이에요.",exampleEn:"It's five people.",note:"Native number used for small counts up to about twenty."},{id:"ko-a1-numbers-006",level:"A1",deck:"numbers",en:"ten (native)",ko:"열",roman:"yeol",exampleKo:"열 개 주세요.",exampleEn:"Give me ten, please.",note:"Native ten. 여섯·일곱·여덟·아홉 are six to nine."},{id:"ko-a1-numbers-007",level:"A1",deck:"numbers",en:"one (Sino)",ko:"일",roman:"il",exampleKo:"일 번 출구로 나가세요.",exampleEn:"Go out through exit number one.",note:"Sino-Korean number. Used for dates, money, phone numbers, and minutes."},{id:"ko-a1-numbers-008",level:"A1",deck:"numbers",en:"ten (Sino)",ko:"십",roman:"sip",exampleKo:"십 분 후에 만나요.",exampleEn:"Let's meet in ten minutes.",note:"Sino ten. 이십 = 20, 삼십 = 30, and so on."},{id:"ko-a1-numbers-009",level:"A1",deck:"numbers",en:"hundred (Sino)",ko:"백",roman:"baek",exampleKo:"이거 백 원이에요.",exampleEn:"This is one hundred won.",note:"Sino hundred. 천 = 1,000 and 만 = 10,000."},{id:"ko-a1-numbers-010",level:"A1",deck:"numbers",en:"How much is it?",ko:"얼마예요?",roman:"eolmayeyo?",exampleKo:"이거 얼마예요?",exampleEn:"How much is this?",note:"The go-to question for prices. Prices use Sino-Korean numbers."},{id:"ko-a1-numbers-011",level:"A1",deck:"numbers",en:"~ item(s) (counter)",ko:"~ 개",roman:"~ gae",exampleKo:"빵 세 개 주세요.",exampleEn:"Three pieces of bread, please.",note:"General counter for objects, used with native numbers (한 개, 두 개...)."},{id:"ko-a1-numbers-012",level:"A1",deck:"numbers",en:"~ person/people (counter)",ko:"~ 명",roman:"~ myeong",exampleKo:"네 명이에요.",exampleEn:"It's four people.",note:"Counter for people, used with native numbers (한 명, 두 명...)."},{id:"ko-a1-food-001",level:"A1",deck:"food",en:"Please give me ~ (I'd like ~)",ko:"~ 주세요",roman:"~ juseyo",exampleKo:"물 주세요.",exampleEn:"Water, please.",note:"The essential ordering phrase. Put the item before 주세요."},{id:"ko-a1-food-002",level:"A1",deck:"food",en:"menu",ko:"메뉴",roman:"menyu",exampleKo:"메뉴 좀 주세요.",exampleEn:"May I have the menu, please?",note:"A loanword from English. 좀 softens the request to 'please'."},{id:"ko-a1-food-003",level:"A1",deck:"food",en:"water",ko:"물",roman:"mul",exampleKo:"물 한 잔 주세요.",exampleEn:"A glass of water, please.",note:"Water is usually free and self-serve in Korean restaurants."},{id:"ko-a1-food-004",level:"A1",deck:"food",en:"rice / meal",ko:"밥",roman:"bap",exampleKo:"밥 먹었어요?",exampleEn:"Have you eaten?",note:"Literally 'rice', but 밥 먹었어요? is also a friendly greeting."},{id:"ko-a1-food-005",level:"A1",deck:"food",en:"kimchi",ko:"김치",roman:"gimchi",exampleKo:"김치 좀 더 주세요.",exampleEn:"A little more kimchi, please.",note:"Side dishes like kimchi are typically refilled for free."},{id:"ko-a1-food-006",level:"A1",deck:"food",en:"It's delicious",ko:"맛있어요",roman:"masisseoyo",exampleKo:"와, 정말 맛있어요!",exampleEn:"Wow, it's really delicious!",note:"Compliment for food. The opposite is 맛없어요 (it's not tasty)."},{id:"ko-a1-food-007",level:"A1",deck:"food",en:"It's spicy",ko:"매워요",roman:"maewoyo",exampleKo:"이거 너무 매워요.",exampleEn:"This is too spicy.",note:"From 맵다. Add 안 for 'not spicy': 안 매워요."},{id:"ko-a1-food-008",level:"A1",deck:"food",en:"I want to eat ~",ko:"~ 먹고 싶어요",roman:"~ meokgo sipeoyo",exampleKo:"비빔밥 먹고 싶어요.",exampleEn:"I want to eat bibimbap.",note:"~고 싶어요 = 'want to'. Attach to a verb stem like 먹- (to eat)."},{id:"ko-a1-food-009",level:"A1",deck:"food",en:"I'll have this one",ko:"이거 주세요",roman:"igeo juseyo",exampleKo:"이거 하나 주세요.",exampleEn:"I'll have one of these.",note:"Point at the menu and say 이거 (this one) when you don't know the name."},{id:"ko-a1-food-010",level:"A1",deck:"food",en:"Check, please",ko:"계산서 주세요",roman:"gyesanseo juseyo",exampleKo:"저기요, 계산서 주세요.",exampleEn:"Excuse me, the check, please.",note:"계산서 = bill. You can also just say 계산할게요 (I'll pay now)."},{id:"ko-a1-food-011",level:"A1",deck:"food",en:"Excuse me! (calling a server)",ko:"저기요",roman:"jeogiyo",exampleKo:"저기요, 여기 주문할게요.",exampleEn:"Excuse me, we'd like to order here.",note:"Standard way to get a server's attention in a restaurant."},{id:"ko-a1-food-012",level:"A1",deck:"food",en:"to go / takeout",ko:"포장",roman:"pojang",exampleKo:"포장해 주세요.",exampleEn:"To go, please.",note:"포장 = packaging. 포장해 주세요 means 'please pack it to go'."},{id:"ko-a1-family-001",level:"A1",deck:"family",en:"family",ko:"가족",roman:"gajok",exampleKo:"우리 가족은 네 명이에요.",exampleEn:"There are four people in my family.",note:"우리 ('our') is often used instead of 'my' for family in Korean."},{id:"ko-a1-family-002",level:"A1",deck:"family",en:"mother / mom",ko:"어머니",roman:"eomeoni",exampleKo:"어머니는 선생님이에요.",exampleEn:"My mother is a teacher.",note:"어머니 is polite; 엄마 (eomma) is the casual 'mom'."},{id:"ko-a1-family-003",level:"A1",deck:"family",en:"father / dad",ko:"아버지",roman:"abeoji",exampleKo:"아버지는 회사원이에요.",exampleEn:"My father is an office worker.",note:"아버지 is polite; 아빠 (appa) is the casual 'dad'."},{id:"ko-a1-family-004",level:"A1",deck:"family",en:"older brother (of a male)",ko:"형",roman:"hyeong",exampleKo:"형이 한 명 있어요.",exampleEn:"I have one older brother.",note:"A male calls his older brother 형. A female uses 오빠 instead."},{id:"ko-a1-family-005",level:"A1",deck:"family",en:"older brother (of a female)",ko:"오빠",roman:"oppa",exampleKo:"오빠는 대학생이에요.",exampleEn:"My older brother is a college student.",note:"Only a female uses 오빠 for an older brother (or older male friend)."},{id:"ko-a1-family-006",level:"A1",deck:"family",en:"older sister (of a male)",ko:"누나",roman:"nuna",exampleKo:"누나가 두 명 있어요.",exampleEn:"I have two older sisters.",note:"A male calls his older sister 누나. A female uses 언니 instead."},{id:"ko-a1-family-007",level:"A1",deck:"family",en:"older sister (of a female)",ko:"언니",roman:"eonni",exampleKo:"언니는 의사예요.",exampleEn:"My older sister is a doctor.",note:"Only a female uses 언니 for an older sister (or older female friend)."},{id:"ko-a1-family-008",level:"A1",deck:"family",en:"younger sibling",ko:"동생",roman:"dongsaeng",exampleKo:"동생이 있어요.",exampleEn:"I have a younger sibling.",note:"동생 covers both sexes. Specify with 남동생 (younger brother) / 여동생 (younger sister)."},{id:"ko-a1-family-009",level:"A1",deck:"family",en:"I have ~ (it exists)",ko:"있어요",roman:"isseoyo",exampleKo:"동생이 한 명 있어요.",exampleEn:"I have one younger sibling.",note:"있어요 means 'there is / I have'. The negative is 없어요."},{id:"ko-a1-family-010",level:"A1",deck:"family",en:"I don't have ~ (none)",ko:"없어요",roman:"eopseoyo",exampleKo:"형제가 없어요.",exampleEn:"I don't have any siblings.",note:"없어요 means 'there isn't / I don't have'. The opposite of 있어요."},{id:"ko-a1-family-011",level:"A1",deck:"family",en:"grandfather",ko:"할아버지",roman:"harabeoji",exampleKo:"할아버지는 부산에 사세요.",exampleEn:"My grandfather lives in Busan.",note:"Use the honorific 사세요 (not 살아요) when speaking about elders."},{id:"ko-a1-family-012",level:"A1",deck:"family",en:"grandmother",ko:"할머니",roman:"halmeoni",exampleKo:"할머니가 요리를 잘하세요.",exampleEn:"My grandmother cooks well.",note:"Pairs with 할아버지. 잘하세요 = '(she) does well', honorific form."},{id:"ko-a2-time-date-001",level:"A2",deck:"time-date",en:"What time is it now?",ko:"지금 몇 시예요?",roman:"jigeum myeot siyeyo?",exampleKo:"실례합니다, 지금 몇 시예요?",exampleEn:"Excuse me, what time is it now?",note:"몇 (myeot) means 'how many/what'; 시 (si) is the counter for the hour."},{id:"ko-a2-time-date-002",level:"A2",deck:"time-date",en:"It's three o'clock.",ko:"세 시예요",roman:"se siyeyo",exampleKo:"지금 세 시예요.",exampleEn:"It's three o'clock now.",note:"Hours use native Korean numbers (한, 두, 세…), not Sino-Korean."},{id:"ko-a2-time-date-003",level:"A2",deck:"time-date",en:"thirty minutes / half past",ko:"삼십 분",roman:"samsip bun",exampleKo:"두 시 삼십 분이에요.",exampleEn:"It's two thirty.",note:"Minutes use Sino-Korean numbers (일, 이, 삼…) + 분 (bun)."},{id:"ko-a2-time-date-004",level:"A2",deck:"time-date",en:"today",ko:"오늘",roman:"oneul",exampleKo:"오늘 날씨가 좋아요.",exampleEn:"The weather is nice today.",note:"Pairs with 어제 (yesterday) and 내일 (tomorrow)."},{id:"ko-a2-time-date-005",level:"A2",deck:"time-date",en:"tomorrow",ko:"내일",roman:"naeil",exampleKo:"내일 만나요.",exampleEn:"Let's meet tomorrow.",note:"Often used with future plans: 내일 + verb in plain form."},{id:"ko-a2-time-date-006",level:"A2",deck:"time-date",en:"yesterday",ko:"어제",roman:"eoje",exampleKo:"어제 친구를 만났어요.",exampleEn:"I met a friend yesterday.",note:"Triggers past tense: 만났어요 (met), 갔어요 (went)."},{id:"ko-a2-time-date-007",level:"A2",deck:"time-date",en:"What day is it?",ko:"무슨 요일이에요?",roman:"museun yoirieyo?",exampleKo:"오늘이 무슨 요일이에요?",exampleEn:"What day is it today?",note:"요일 (yoil) = day of the week; 무슨 (museun) = which/what."},{id:"ko-a2-time-date-008",level:"A2",deck:"time-date",en:"Monday",ko:"월요일",roman:"woryoil",exampleKo:"월요일에 회의가 있어요.",exampleEn:"There's a meeting on Monday.",note:"Days end in 요일: 화(Tue), 수(Wed), 목(Thu), 금(Fri)."},{id:"ko-a2-time-date-009",level:"A2",deck:"time-date",en:"the weekend",ko:"주말",roman:"jumal",exampleKo:"주말에 뭐 해요?",exampleEn:"What do you do on the weekend?",note:"주말 = weekend; 평일 (pyeongil) = weekday."},{id:"ko-a2-time-date-010",level:"A2",deck:"time-date",en:"What's the date today?",ko:"오늘 며칠이에요?",roman:"oneul myeochirieyo?",exampleKo:"오늘 며칠이에요? 6월 6일이에요.",exampleEn:"What's the date today? It's June 6th.",note:"며칠 (myeochil) asks the day-of-month; answer with Sino-Korean number + 일."},{id:"ko-a2-time-date-011",level:"A2",deck:"time-date",en:"in the morning",ko:"아침에",roman:"achime",exampleKo:"아침에 운동해요.",exampleEn:"I exercise in the morning.",note:"Time words take the particle 에 (e) to mean 'at/in'."},{id:"ko-a2-time-date-012",level:"A2",deck:"time-date",en:"in the evening",ko:"저녁에",roman:"jeonyeoge",exampleKo:"저녁에 가족과 밥을 먹어요.",exampleEn:"In the evening I eat with my family.",note:"저녁 also means 'dinner'; 점심 (jeomsim) = lunch / midday."},{id:"ko-a2-shopping-001",level:"A2",deck:"shopping",en:"How much is it?",ko:"얼마예요?",roman:"eolmayeyo?",exampleKo:"이거 얼마예요?",exampleEn:"How much is this?",note:"The essential shopping phrase. 이거 (igeo) = this one."},{id:"ko-a2-shopping-002",level:"A2",deck:"shopping",en:"It's too expensive.",ko:"너무 비싸요",roman:"neomu bissayo",exampleKo:"이건 너무 비싸요.",exampleEn:"This is too expensive.",note:"너무 (neomu) = too/very; opposite of 싸요 (cheap)."},{id:"ko-a2-shopping-003",level:"A2",deck:"shopping",en:"cheap / inexpensive",ko:"싸요",roman:"ssayo",exampleKo:"이 가게는 과일이 싸요.",exampleEn:"Fruit is cheap at this store.",note:"Dictionary form is 싸다 (ssada)."},{id:"ko-a2-shopping-004",level:"A2",deck:"shopping",en:"Please give me this one.",ko:"이거 주세요",roman:"igeo juseyo",exampleKo:"이거 하나 주세요.",exampleEn:"Please give me one of these.",note:"주세요 (juseyo) = please give; add 하나 (one) to specify quantity."},{id:"ko-a2-shopping-005",level:"A2",deck:"shopping",en:"Can I try it on?",ko:"입어 봐도 돼요?",roman:"ibeo bwado dwaeyo?",exampleKo:"이 옷 입어 봐도 돼요?",exampleEn:"Can I try on these clothes?",note:"-아/어 봐도 돼요? asks permission to try doing something."},{id:"ko-a2-shopping-006",level:"A2",deck:"shopping",en:"Do you have a bigger size?",ko:"더 큰 거 있어요?",roman:"deo keun geo isseoyo?",exampleKo:"이거 말고 더 큰 거 있어요?",exampleEn:"Do you have a bigger one than this?",note:"더 (deo) = more; 큰 거 = a big one; 작은 거 = a small one."},{id:"ko-a2-shopping-007",level:"A2",deck:"shopping",en:"I'm just looking.",ko:"그냥 구경하는 거예요",roman:"geunyang gugyeonghaneun geoyeyo",exampleKo:"괜찮아요, 그냥 구경하는 거예요.",exampleEn:"It's okay, I'm just looking.",note:"Polite way to decline help from a shop clerk."},{id:"ko-a2-shopping-008",level:"A2",deck:"shopping",en:"Can I pay by card?",ko:"카드로 계산할 수 있어요?",roman:"kadeuro gyesanhal su isseoyo?",exampleKo:"여기 카드로 계산할 수 있어요?",exampleEn:"Can I pay by card here?",note:"-(으)ㄹ 수 있어요? asks if something is possible. 현금 (cash) = hyeongeum."},{id:"ko-a2-shopping-009",level:"A2",deck:"shopping",en:"Please give me a discount.",ko:"좀 깎아 주세요",roman:"jom kkakka juseyo",exampleKo:"조금 비싸요. 좀 깎아 주세요.",exampleEn:"It's a bit pricey. Please give me a discount.",note:"Common at markets. 깎다 (kkakkda) = to cut down (a price)."},{id:"ko-a2-shopping-010",level:"A2",deck:"shopping",en:"I'll take this one.",ko:"이걸로 할게요",roman:"igeollo halgeyo",exampleKo:"다 봤어요. 이걸로 할게요.",exampleEn:"I've seen everything. I'll take this one.",note:"이걸로 = with this one; -ㄹ게요 states your decision."},{id:"ko-a2-shopping-011",level:"A2",deck:"shopping",en:"Where is the fitting room?",ko:"탈의실이 어디예요?",roman:"taruisiri eodiyeyo?",exampleKo:"탈의실이 어디예요?",exampleEn:"Where is the fitting room?",note:"탈의실 = fitting room; 계산대 (gyesandae) = the checkout counter."},{id:"ko-a2-shopping-012",level:"A2",deck:"shopping",en:"Please give me a receipt.",ko:"영수증 주세요",roman:"yeongsujeung juseyo",exampleKo:"영수증 주세요.",exampleEn:"Please give me a receipt.",note:"영수증 = receipt; 봉투 (bongtu) = a bag."},{id:"ko-a2-transport-001",level:"A2",deck:"transport",en:"Where is the subway station?",ko:"지하철역이 어디예요?",roman:"jihacheoryeogi eodiyeyo?",exampleKo:"지하철역이 어디예요?",exampleEn:"Where is the subway station?",note:"지하철 = subway; 역 (yeok) = station."},{id:"ko-a2-transport-002",level:"A2",deck:"transport",en:"Does this bus go to Seoul Station?",ko:"이 버스 서울역에 가요?",roman:"i beoseu seoullyeoge gayo?",exampleKo:"이 버스 서울역에 가요?",exampleEn:"Does this bus go to Seoul Station?",note:"Destination + 에 가요? asks whether it goes there."},{id:"ko-a2-transport-003",level:"A2",deck:"transport",en:"How long does it take?",ko:"얼마나 걸려요?",roman:"eolmana geollyeoyo?",exampleKo:"여기서 공항까지 얼마나 걸려요?",exampleEn:"How long does it take from here to the airport?",note:"걸리다 (geollida) = to take (time). 까지 (kkaji) = up to/until."},{id:"ko-a2-transport-004",level:"A2",deck:"transport",en:"Please take me to this address.",ko:"이 주소로 가 주세요",roman:"i jusoro ga juseyo",exampleKo:"기사님, 이 주소로 가 주세요.",exampleEn:"Driver, please take me to this address.",note:"Used in taxis. 기사님 (gisanim) = driver (polite)."},{id:"ko-a2-transport-005",level:"A2",deck:"transport",en:"Please stop here.",ko:"여기서 세워 주세요",roman:"yeogiseo sewo juseyo",exampleKo:"저기 신호등에서 세워 주세요.",exampleEn:"Please stop at the traffic light over there.",note:"세우다 (seuda) = to stop/pull over (a vehicle)."},{id:"ko-a2-transport-006",level:"A2",deck:"transport",en:"Where do I transfer?",ko:"어디에서 갈아타요?",roman:"eodieseo garatayo?",exampleKo:"2호선은 어디에서 갈아타요?",exampleEn:"Where do I transfer to line 2?",note:"갈아타다 (garatada) = to transfer (trains/buses)."},{id:"ko-a2-transport-007",level:"A2",deck:"transport",en:"by subway",ko:"지하철로",roman:"jihacheollo",exampleKo:"회사에 지하철로 가요.",exampleEn:"I go to work by subway.",note:"(으)로 marks the means of transport: 버스로, 택시로."},{id:"ko-a2-transport-008",level:"A2",deck:"transport",en:"Which exit should I take?",ko:"몇 번 출구로 나가요?",roman:"myeot beon chulguro nagayo?",exampleKo:"백화점은 몇 번 출구로 나가요?",exampleEn:"Which exit do I take for the department store?",note:"출구 = exit; numbered with Sino-Korean + 번 (beon)."},{id:"ko-a2-transport-009",level:"A2",deck:"transport",en:"Please go straight.",ko:"쭉 가세요",roman:"jjuk gaseyo",exampleKo:"여기서 쭉 가세요.",exampleEn:"Go straight from here.",note:"쭉 (jjuk) = straight/all the way. Often heard giving directions."},{id:"ko-a2-transport-010",level:"A2",deck:"transport",en:"Please turn left.",ko:"왼쪽으로 가세요",roman:"oenjjogeuro gaseyo",exampleKo:"저 모퉁이에서 왼쪽으로 가세요.",exampleEn:"Turn left at that corner.",note:"왼쪽 = left, 오른쪽 (oreunjjok) = right."},{id:"ko-a2-transport-011",level:"A2",deck:"transport",en:"Is it far from here?",ko:"여기서 멀어요?",roman:"yeogiseo meoreoyo?",exampleKo:"지하철역이 여기서 멀어요?",exampleEn:"Is the subway station far from here?",note:"멀다 (meolda) = far; 가깝다 (gakkapda) = close/near."},{id:"ko-a2-transport-012",level:"A2",deck:"transport",en:"I missed the bus.",ko:"버스를 놓쳤어요",roman:"beoseureul nochyeosseoyo",exampleKo:"늦어서 버스를 놓쳤어요.",exampleEn:"I was late, so I missed the bus.",note:"놓치다 (nochida) = to miss (a bus/train); past form 놓쳤어요."},{id:"ko-a2-weather-001",level:"A2",deck:"weather",en:"How's the weather today?",ko:"오늘 날씨 어때요?",roman:"oneul nalssi eottaeyo?",exampleKo:"오늘 날씨 어때요?",exampleEn:"How's the weather today?",note:"어때요? (eottaeyo?) = how is it? A very common opener."},{id:"ko-a2-weather-002",level:"A2",deck:"weather",en:"The weather is nice.",ko:"날씨가 좋아요",roman:"nalssiga joayo",exampleKo:"오늘은 날씨가 정말 좋아요.",exampleEn:"The weather is really nice today.",note:"좋다 (jota) = good; 나쁘다 (nappeuda) = bad."},{id:"ko-a2-weather-003",level:"A2",deck:"weather",en:"It's hot.",ko:"더워요",roman:"deowoyo",exampleKo:"여름이라서 너무 더워요.",exampleEn:"It's summer, so it's really hot.",note:"Dictionary form 덥다 (deopda); opposite 춥다 (cold)."},{id:"ko-a2-weather-004",level:"A2",deck:"weather",en:"It's cold.",ko:"추워요",roman:"chuwoyo",exampleKo:"밖이 추워요. 따뜻하게 입으세요.",exampleEn:"It's cold outside. Dress warmly.",note:"Dictionary form 춥다 (chupda). For things/food use 차가워요."},{id:"ko-a2-weather-005",level:"A2",deck:"weather",en:"It's raining.",ko:"비가 와요",roman:"biga wayo",exampleKo:"지금 밖에 비가 와요.",exampleEn:"It's raining outside now.",note:"Literally 'rain comes'. 눈이 와요 = it's snowing."},{id:"ko-a2-weather-006",level:"A2",deck:"weather",en:"It's snowing.",ko:"눈이 와요",roman:"nuni wayo",exampleKo:"겨울이라서 눈이 와요.",exampleEn:"It's snowing because it's winter.",note:"눈 means both 'snow' and 'eye' — context decides."},{id:"ko-a2-weather-007",level:"A2",deck:"weather",en:"It's windy.",ko:"바람이 불어요",roman:"barami bureoyo",exampleKo:"오늘은 바람이 많이 불어요.",exampleEn:"It's very windy today.",note:"불다 (bulda) = to blow; 많이 (mani) = a lot."},{id:"ko-a2-weather-008",level:"A2",deck:"weather",en:"It's warm.",ko:"따뜻해요",roman:"ttatteutaeyo",exampleKo:"봄이라서 날씨가 따뜻해요.",exampleEn:"It's warm because it's spring.",note:"따뜻하다 = pleasantly warm; 시원하다 = pleasantly cool."},{id:"ko-a2-weather-009",level:"A2",deck:"weather",en:"spring",ko:"봄",roman:"bom",exampleKo:"봄에 꽃이 많이 피어요.",exampleEn:"Many flowers bloom in spring.",note:"Four seasons: 봄, 여름(summer), 가을(autumn), 겨울(winter)."},{id:"ko-a2-weather-010",level:"A2",deck:"weather",en:"summer",ko:"여름",roman:"yeoreum",exampleKo:"한국의 여름은 덥고 습해요.",exampleEn:"Summer in Korea is hot and humid.",note:"-고 (go) links two adjectives: 덥고 습해요 (hot and humid)."},{id:"ko-a2-weather-011",level:"A2",deck:"weather",en:"Please bring an umbrella.",ko:"우산을 가져가세요",roman:"usaneul gajyeogaseyo",exampleKo:"비가 오니까 우산을 가져가세요.",exampleEn:"It's raining, so please bring an umbrella.",note:"-(으)니까 gives a reason. 우산 = umbrella."},{id:"ko-a2-weather-012",level:"A2",deck:"weather",en:"It might rain tomorrow.",ko:"내일 비가 올 것 같아요",roman:"naeil biga ol geot gatayo",exampleKo:"구름이 많아서 내일 비가 올 것 같아요.",exampleEn:"It's cloudy, so it might rain tomorrow.",note:"-(으)ㄹ 것 같아요 = I think / it seems (a soft guess)."},{id:"ko-a2-hobby-001",level:"A2",deck:"hobby",en:"What's your hobby?",ko:"취미가 뭐예요?",roman:"chwimiga mwoyeyo?",exampleKo:"시간 있을 때 취미가 뭐예요?",exampleEn:"What's your hobby in your free time?",note:"취미 = hobby; 뭐예요? = what is it?"},{id:"ko-a2-hobby-002",level:"A2",deck:"hobby",en:"I like watching movies.",ko:"영화 보는 걸 좋아해요",roman:"yeonghwa boneun geol joahaeyo",exampleKo:"저는 영화 보는 걸 좋아해요.",exampleEn:"I like watching movies.",note:"Verb + -는 걸 좋아해요 = I like doing (the verb)."},{id:"ko-a2-hobby-003",level:"A2",deck:"hobby",en:"I listen to music.",ko:"음악을 들어요",roman:"eumageul deureoyo",exampleKo:"쉴 때 음악을 들어요.",exampleEn:"I listen to music when I rest.",note:"듣다 (deutda) becomes 들어요 (irregular ㄷ → ㄹ)."},{id:"ko-a2-hobby-004",level:"A2",deck:"hobby",en:"I exercise.",ko:"운동해요",roman:"undonghaeyo",exampleKo:"건강을 위해서 매일 운동해요.",exampleEn:"I exercise every day for my health.",note:"운동하다 = to exercise; 매일 (maeil) = every day."},{id:"ko-a2-hobby-005",level:"A2",deck:"hobby",en:"I read books.",ko:"책을 읽어요",roman:"chaegeul ilgeoyo",exampleKo:"주말에 카페에서 책을 읽어요.",exampleEn:"I read books at a cafe on weekends.",note:"읽다 (ikda) = to read; 책 (chaek) = book."},{id:"ko-a2-hobby-006",level:"A2",deck:"hobby",en:"I like to travel.",ko:"여행을 좋아해요",roman:"yeohaengeul joahaeyo",exampleKo:"저는 새로운 곳으로 여행하는 걸 좋아해요.",exampleEn:"I like traveling to new places.",note:"여행 = travel/trip; 여행하다 = to travel."},{id:"ko-a2-hobby-007",level:"A2",deck:"hobby",en:"I'm learning to cook.",ko:"요리를 배워요",roman:"yorireul baewoyo",exampleKo:"요즘 한국 요리를 배워요.",exampleEn:"These days I'm learning Korean cooking.",note:"배우다 (baeuda) = to learn; 요리 = cooking/dish."},{id:"ko-a2-hobby-008",level:"A2",deck:"hobby",en:"I play games.",ko:"게임을 해요",roman:"geimeul haeyo",exampleKo:"친구들과 같이 게임을 해요.",exampleEn:"I play games with my friends.",note:"-와/과 같이 = together with. 게임하다 = to game."},{id:"ko-a2-hobby-009",level:"A2",deck:"hobby",en:"I take photos.",ko:"사진을 찍어요",roman:"sajineul jjigeoyo",exampleKo:"여행할 때 사진을 많이 찍어요.",exampleEn:"I take a lot of photos when I travel.",note:"찍다 (jjikda) = to take (a photo); 사진 = photo."},{id:"ko-a2-hobby-010",level:"A2",deck:"hobby",en:"How often do you do it?",ko:"얼마나 자주 해요?",roman:"eolmana jaju haeyo?",exampleKo:"운동을 얼마나 자주 해요?",exampleEn:"How often do you exercise?",note:"자주 (jaju) = often; 가끔 (gakkeum) = sometimes."},{id:"ko-a2-hobby-011",level:"A2",deck:"hobby",en:"Let's do it together sometime.",ko:"다음에 같이 해요",roman:"daeume gachi haeyo",exampleKo:"재미있겠어요! 다음에 같이 해요.",exampleEn:"That sounds fun! Let's do it together sometime.",note:"다음에 = next time/sometime; 같이 (gachi) = together."},{id:"ko-a2-hobby-012",level:"A2",deck:"hobby",en:"It's fun.",ko:"재미있어요",roman:"jaemiisseoyo",exampleKo:"이 취미는 정말 재미있어요.",exampleEn:"This hobby is really fun.",note:"재미있다 = fun/interesting; 재미없다 = boring."},{id:"ko-b1-work-001",level:"B1",deck:"work",en:"to be in a meeting",ko:"회의 중이다",roman:"hoeui jungida",exampleKo:"지금 회의 중이라서 나중에 전화드릴게요.",exampleEn:"I'm in a meeting right now, so I'll call you later.",note:"Use the '-중이다' pattern to say you're in the middle of something."},{id:"ko-b1-work-002",level:"B1",deck:"work",en:"to submit a report",ko:"보고서를 제출하다",roman:"bogoseoreul jechulhada",exampleKo:"내일까지 보고서를 제출해야 해요.",exampleEn:"I have to submit the report by tomorrow.",note:"제출하다 (to submit) is more formal than 내다 in the workplace."},{id:"ko-b1-work-003",level:"B1",deck:"work",en:"to work overtime",ko:"야근하다",roman:"yageunhada",exampleKo:"이번 주에는 매일 야근했어요.",exampleEn:"I worked overtime every day this week.",note:"야근 literally means 'night work' — common in Korean office life."},{id:"ko-b1-work-004",level:"B1",deck:"work",en:"to meet a deadline",ko:"마감을 맞추다",roman:"magameul matchuda",exampleKo:"마감을 맞추려고 주말에도 일했어요.",exampleEn:"I worked on the weekend too in order to meet the deadline.",note:"맞추다 here means 'to make something fit/align' with the deadline."},{id:"ko-b1-work-005",level:"B1",deck:"work",en:"to take a day off",ko:"휴가를 내다",roman:"hyugareul naeda",exampleKo:"다음 주에 하루 휴가를 내려고 해요.",exampleEn:"I'm planning to take a day off next week.",note:"휴가를 내다 = to put in for leave. 연차 specifically means annual leave."},{id:"ko-b1-work-006",level:"B1",deck:"work",en:"to be in charge of",ko:"담당하다",roman:"damdanghada",exampleKo:"제가 이 프로젝트를 담당하고 있어요.",exampleEn:"I'm in charge of this project.",note:"담당자 means 'the person in charge / point of contact'."},{id:"ko-b1-work-007",level:"B1",deck:"work",en:"to discuss / talk over",ko:"의논하다",roman:"uinonhada",exampleKo:"그 문제는 팀장님과 의논해 볼게요.",exampleEn:"I'll discuss that issue with the team leader.",note:"의논하다 implies seeking advice; 상의하다 is a close synonym."},{id:"ko-b1-work-008",level:"B1",deck:"work",en:"in my opinion",ko:"제 생각에는",roman:"je saenggageneun",exampleKo:"제 생각에는 이 방법이 더 좋을 것 같아요.",exampleEn:"In my opinion, this method seems better.",note:"A polite way to open an opinion. 제 = humble 'my'."},{id:"ko-b1-work-009",level:"B1",deck:"work",en:"to be busy with work",ko:"일이 바쁘다",roman:"iri bappeuda",exampleKo:"요즘 일이 너무 바빠서 정신이 없어요.",exampleEn:"I'm so busy with work these days that I'm overwhelmed.",note:"정신이 없다 ('to have no mind') idiomatically means 'to be hectic'."},{id:"ko-b1-work-010",level:"B1",deck:"work",en:"to send an email",ko:"이메일을 보내다",roman:"imeireul bonaeda",exampleKo:"자세한 내용은 이메일로 보내 드릴게요.",exampleEn:"I'll send you the details by email.",note:"메일 보내다 is the common short form in spoken Korean."},{id:"ko-b1-work-011",level:"B1",deck:"work",en:"to ask a favor",ko:"부탁을 드리다",roman:"butageul deurida",exampleKo:"바쁘시겠지만 부탁 좀 드려도 될까요?",exampleEn:"I know you're busy, but may I ask you a favor?",note:"드리다 is the humble form of 주다, used when asking up the hierarchy."},{id:"ko-b1-work-012",level:"B1",deck:"work",en:"good work / well done (to coworkers)",ko:"수고하셨습니다",roman:"sugohasyeotseumnida",exampleKo:"오늘 다들 수고하셨습니다.",exampleEn:"Everyone did a great job today.",note:"Said at the end of work to acknowledge others' effort. Very common."},{id:"ko-b1-health-001",level:"B1",deck:"health",en:"I have a cold",ko:"감기에 걸리다",roman:"gamgie geollida",exampleKo:"어제부터 감기에 걸려서 목이 아파요.",exampleEn:"I caught a cold yesterday, so my throat hurts.",note:"Use the particle 에 + 걸리다 ('to be caught by') for illnesses."},{id:"ko-b1-health-002",level:"B1",deck:"health",en:"to have a fever",ko:"열이 나다",roman:"yeori nada",exampleKo:"아이가 열이 나서 병원에 갔어요.",exampleEn:"My child had a fever, so we went to the hospital.",note:"나다 ('to come out') pairs with many symptoms: 열, 기침, 콧물."},{id:"ko-b1-health-003",level:"B1",deck:"health",en:"my whole body aches",ko:"온몸이 아프다",roman:"onmomi apeuda",exampleKo:"몸살이 났는지 온몸이 아파요.",exampleEn:"My whole body aches — I think I'm coming down with something.",note:"몸살 is the body aches/fatigue of a cold; 몸살이 나다 = to get run down."},{id:"ko-b1-health-004",level:"B1",deck:"health",en:"to see a doctor",ko:"진료를 받다",roman:"jillyoreul batda",exampleKo:"증상이 심해서 진료를 받으러 왔어요.",exampleEn:"My symptoms got worse, so I came to see a doctor.",note:"진료 = medical examination. 진찰을 받다 is a close synonym."},{id:"ko-b1-health-005",level:"B1",deck:"health",en:"to prescribe medicine",ko:"약을 처방하다",roman:"yageul cheobanghada",exampleKo:"의사 선생님이 약을 처방해 주셨어요.",exampleEn:"The doctor prescribed me some medicine.",note:"From the patient's side, you 약을 처방받다 (get a prescription)."},{id:"ko-b1-health-006",level:"B1",deck:"health",en:"to take medicine",ko:"약을 먹다",roman:"yageul meokda",exampleKo:"하루에 세 번 식후에 약을 드세요.",exampleEn:"Take the medicine three times a day after meals.",note:"Korean uses 먹다 ('to eat') for taking medicine, not 마시다."},{id:"ko-b1-health-007",level:"B1",deck:"health",en:"to get some rest",ko:"푹 쉬다",roman:"puk swida",exampleKo:"무리하지 말고 푹 쉬세요.",exampleEn:"Don't overdo it and get plenty of rest.",note:"푹 is an adverb meaning 'thoroughly/deeply' — 푹 쉬다, 푹 자다."},{id:"ko-b1-health-008",level:"B1",deck:"health",en:"to get better / recover",ko:"낫다",roman:"natda",exampleKo:"약을 먹으니까 좀 나았어요.",exampleEn:"I feel a bit better after taking the medicine.",note:"Irregular ㅅ verb: 낫다 → 나아요, 나았어요. Also means 'to be better'."},{id:"ko-b1-health-009",level:"B1",deck:"health",en:"to be careful / take care",ko:"조심하다",roman:"josimhada",exampleKo:"감기 걸리지 않게 조심하세요.",exampleEn:"Be careful not to catch a cold.",note:"감기 조심하세요 is a common caring farewell in cold weather."},{id:"ko-b1-health-010",level:"B1",deck:"health",en:"Where does it hurt?",ko:"어디가 아프세요?",roman:"eodiga apeuseyo?",exampleKo:"어디가 아프세요? 증상을 말씀해 주세요.",exampleEn:"Where does it hurt? Please describe your symptoms.",note:"What a doctor or pharmacist asks first. 아프세요 is the polite form."},{id:"ko-b1-health-011",level:"B1",deck:"health",en:"to make a reservation (appointment)",ko:"예약하다",roman:"yeyakhada",exampleKo:"병원에 미리 예약하고 가는 게 좋아요.",exampleEn:"It's better to make an appointment before going to the hospital.",note:"Used for clinics, restaurants, hotels — anything booked in advance."},{id:"ko-b1-travel-001",level:"B1",deck:"travel",en:"to book a flight ticket",ko:"비행기 표를 예매하다",roman:"bihaenggi pyoreul yemaehada",exampleKo:"다음 달 비행기 표를 벌써 예매했어요.",exampleEn:"I already booked the flight ticket for next month.",note:"예매하다 = to book tickets in advance (transport, movies, shows)."},{id:"ko-b1-travel-002",level:"B1",deck:"travel",en:"to check in (hotel)",ko:"체크인하다",roman:"chekeuinhada",exampleKo:"보통 체크인은 오후 세 시부터예요.",exampleEn:"Check-in usually starts at 3 p.m.",note:"Loanword from English. Checkout is 체크아웃하다."},{id:"ko-b1-travel-003",level:"B1",deck:"travel",en:"How do I get to...?",ko:"어떻게 가요?",roman:"eotteoke gayo?",exampleKo:"여기에서 시청까지 어떻게 가요?",exampleEn:"How do I get from here to City Hall?",note:"Put the destination before 까지 (to/until): 시청까지 어떻게 가요?"},{id:"ko-b1-travel-004",level:"B1",deck:"travel",en:"to transfer (trains/buses)",ko:"갈아타다",roman:"garatada",exampleKo:"여기에서 2호선으로 갈아타세요.",exampleEn:"Transfer to Line 2 here.",note:"환승하다 is the more formal/written equivalent."},{id:"ko-b1-travel-005",level:"B1",deck:"travel",en:"to get lost / lose one's way",ko:"길을 잃다",roman:"gireul ilta",exampleKo:"지도를 봤는데도 길을 잃었어요.",exampleEn:"Even though I looked at the map, I got lost.",note:"-는데도 means 'even though' — useful for contrasting results."},{id:"ko-b1-travel-006",level:"B1",deck:"travel",en:"Could you recommend...?",ko:"추천해 주시겠어요?",roman:"chucheonhae jusigesseoyo?",exampleKo:"이 근처에 맛있는 식당 좀 추천해 주시겠어요?",exampleEn:"Could you recommend a good restaurant nearby?",note:"-아/어 주시겠어요? is a very polite request pattern."},{id:"ko-b1-travel-007",level:"B1",deck:"travel",en:"to take a picture",ko:"사진을 찍다",roman:"sajineul jjikda",exampleKo:"실례지만 사진 좀 찍어 주실 수 있어요?",exampleEn:"Excuse me, could you take a picture for us?",note:"찍어 주다 = take a photo for someone else's benefit."},{id:"ko-b1-travel-008",level:"B1",deck:"travel",en:"It's worth seeing / a must-see",ko:"볼 만하다",roman:"bol manhada",exampleKo:"경복궁은 한번 볼 만해요.",exampleEn:"Gyeongbokgung Palace is worth seeing.",note:"-(으)ㄹ 만하다 means 'worth doing'. 갈 만하다, 먹을 만하다 too."},{id:"ko-b1-travel-009",level:"B1",deck:"travel",en:"to exchange money",ko:"환전하다",roman:"hwanjeonhada",exampleKo:"공항에서 환전하면 수수료가 비싸요.",exampleEn:"If you exchange money at the airport, the fee is high.",note:"수수료 = service/handling fee, useful for banking and travel."},{id:"ko-b1-travel-010",level:"B1",deck:"travel",en:"How much is the fare?",ko:"요금이 얼마예요?",roman:"yogeumi eolmayeyo?",exampleKo:"택시 요금이 얼마예요?",exampleEn:"How much is the taxi fare?",note:"요금 = fare/charge (transport, utilities); 값/가격 = price of goods."},{id:"ko-b1-travel-011",level:"B1",deck:"travel",en:"to cancel a reservation",ko:"예약을 취소하다",roman:"yeyageul chwisohada",exampleKo:"일정이 바뀌어서 예약을 취소해야 해요.",exampleEn:"My schedule changed, so I have to cancel the reservation.",note:"취소하다 = to cancel; 변경하다 = to change/modify."},{id:"ko-b1-travel-012",level:"B1",deck:"travel",en:"Have a safe trip",ko:"잘 다녀오세요",roman:"jal danyeooseyo",exampleKo:"여행 잘 다녀오세요!",exampleEn:"Have a safe trip!",note:"Said to someone leaving and coming back. They reply 다녀오겠습니다."},{id:"ko-b1-feelings-001",level:"B1",deck:"feelings",en:"to be in a good mood",ko:"기분이 좋다",roman:"gibuni jota",exampleKo:"오늘은 날씨가 좋아서 기분이 좋아요.",exampleEn:"The weather is nice today, so I'm in a good mood.",note:"기분 = mood/feeling at the moment; 감정 = emotion in general."},{id:"ko-b1-feelings-002",level:"B1",deck:"feelings",en:"to be upset / in a bad mood",ko:"기분이 나쁘다",roman:"gibuni nappeuda",exampleKo:"그 말을 듣고 기분이 나빴어요.",exampleEn:"I felt bad after hearing that.",note:"기분이 상하다 ('mood gets hurt') is a softer way to say offended."},{id:"ko-b1-feelings-003",level:"B1",deck:"feelings",en:"to be worried",ko:"걱정되다",roman:"geokjeongdoeda",exampleKo:"시험 결과가 걱정돼요.",exampleEn:"I'm worried about the test results.",note:"걱정되다 = to feel worried; 걱정하다 = to worry (active). 걱정하지 마세요 = don't worry."},{id:"ko-b1-feelings-004",level:"B1",deck:"feelings",en:"to be excited / look forward to",ko:"기대되다",roman:"gidaedoeda",exampleKo:"내일 여행이 정말 기대돼요.",exampleEn:"I'm really looking forward to the trip tomorrow.",note:"기대 = expectation/anticipation. 기대돼요 = I can't wait."},{id:"ko-b1-feelings-005",level:"B1",deck:"feelings",en:"to be disappointed",ko:"실망하다",roman:"silmanghada",exampleKo:"기대를 많이 해서 그런지 좀 실망했어요.",exampleEn:"Maybe because I expected a lot, I was a bit disappointed.",note:"-아/어서 그런지 = 'maybe because...' — softens a guess about a reason."},{id:"ko-b1-feelings-006",level:"B1",deck:"feelings",en:"to be nervous",ko:"긴장되다",roman:"ginjangdoeda",exampleKo:"면접 때문에 너무 긴장돼요.",exampleEn:"I'm so nervous because of the interview.",note:"긴장 = tension/nerves. 긴장을 풀다 = to relax/release the tension."},{id:"ko-b1-feelings-007",level:"B1",deck:"feelings",en:"to feel relieved",ko:"마음이 놓이다",roman:"maeumi noida",exampleKo:"네가 무사하다니 마음이 놓이네.",exampleEn:"I'm relieved to hear that you're safe.",note:"Literally 'the heart is set down'. 다행이다 also means 'what a relief'."},{id:"ko-b1-feelings-008",level:"B1",deck:"feelings",en:"I understand how you feel",ko:"그 마음 이해해요",roman:"geu maeum ihaehaeyo",exampleKo:"힘들겠지만 그 마음 이해해요.",exampleEn:"It must be hard, but I understand how you feel.",note:"A warm empathy phrase. 공감하다 = to empathize/relate."},{id:"ko-b1-feelings-009",level:"B1",deck:"feelings",en:"Cheer up / Stay strong",ko:"힘내세요",roman:"himnaeseyo",exampleKo:"너무 속상해하지 말고 힘내세요.",exampleEn:"Don't be too upset — stay strong.",note:"Literally 'put out strength'. The go-to phrase to encourage someone."},{id:"ko-b1-feelings-010",level:"B1",deck:"feelings",en:"to be touched / moved",ko:"감동받다",roman:"gamdongbatda",exampleKo:"편지를 읽고 정말 감동받았어요.",exampleEn:"I was really moved after reading the letter.",note:"감동 = deep emotional impact. 감동적이다 = to be touching/moving."},{id:"ko-b1-feelings-011",level:"B1",deck:"feelings",en:"to be annoyed / fed up",ko:"짜증이 나다",roman:"jjajeungi nada",exampleKo:"일이 자꾸 안 풀려서 짜증이 나요.",exampleEn:"Things keep not working out, so I'm getting annoyed.",note:"짜증 is everyday irritation. Casual: 짜증 나 ('ugh, so annoying')."},{id:"ko-b1-appointment-001",level:"B1",deck:"appointment",en:"to make plans / set a date",ko:"약속을 잡다",roman:"yaksogeul japda",exampleKo:"이번 주말에 친구랑 약속을 잡았어요.",exampleEn:"I made plans with a friend for this weekend.",note:"약속 = a promise or an appointment. 약속을 잡다 = to set up a meeting."},{id:"ko-b1-appointment-002",level:"B1",deck:"appointment",en:"Are you free / available?",ko:"시간 괜찮으세요?",roman:"sigan gwaenchaneuseyo?",exampleKo:"내일 오후에 시간 괜찮으세요?",exampleEn:"Are you free tomorrow afternoon?",note:"Polite way to ask availability. 시간 있으세요? is a bit more direct."},{id:"ko-b1-appointment-003",level:"B1",deck:"appointment",en:"to be late / run late",ko:"늦다",roman:"neutda",exampleKo:"길이 막혀서 조금 늦을 것 같아요.",exampleEn:"The traffic is bad, so I think I'll be a little late.",note:"-(으)ㄹ 것 같아요 = 'I think it'll...' — softens predictions politely."},{id:"ko-b1-appointment-004",level:"B1",deck:"appointment",en:"to reschedule / change plans",ko:"약속을 미루다",roman:"yaksogeul miruda",exampleKo:"갑자기 일이 생겨서 약속을 미뤄도 될까요?",exampleEn:"Something came up — could we push the appointment back?",note:"미루다 = to postpone/put off. 앞당기다 = to move up (earlier)."},{id:"ko-b1-appointment-005",level:"B1",deck:"appointment",en:"Something came up",ko:"일이 생기다",roman:"iri saenggida",exampleKo:"급한 일이 생겨서 못 갈 것 같아요.",exampleEn:"Something urgent came up, so I don't think I can go.",note:"생기다 = to come about/arise. 급한 일 = an urgent matter."},{id:"ko-b1-appointment-006",level:"B1",deck:"appointment",en:"to confirm / check (a plan)",ko:"확인하다",roman:"hwaginhada",exampleKo:"약속 시간을 다시 한번 확인하고 싶어요.",exampleEn:"I'd like to confirm the appointment time once more.",note:"확인하다 = to confirm/verify. 다시 한번 = once more, one more time."},{id:"ko-b1-appointment-007",level:"B1",deck:"appointment",en:"Let's meet at...",ko:"에서 만나요",roman:"eseo mannayo",exampleKo:"그럼 강남역에서 만나요.",exampleEn:"Then let's meet at Gangnam Station.",note:"Place + 에서 marks where an action happens. 만나다 takes 에서, not 에."},{id:"ko-b1-appointment-008",level:"B1",deck:"appointment",en:"to be on time / make it in time",ko:"시간을 지키다",roman:"siganeul jikida",exampleKo:"약속 시간을 잘 지키는 사람이 좋아요.",exampleEn:"I like people who are punctual.",note:"지키다 = to keep/protect; 약속을 지키다 = to keep a promise."},{id:"ko-b1-appointment-009",level:"B1",deck:"appointment",en:"When works for you?",ko:"언제가 좋으세요?",roman:"eonjega joeuseyo?",exampleKo:"다음 주 중에 언제가 좋으세요?",exampleEn:"Sometime next week, when works for you?",note:"Polite way to let the other person pick a time. 중에 = among/during."},{id:"ko-b1-appointment-010",level:"B1",deck:"appointment",en:"to look forward to (seeing you)",ko:"기다리고 있을게요",roman:"gidarigo isseulgeyo",exampleKo:"그날 뵙기를 기다리고 있을게요.",exampleEn:"I'll be looking forward to seeing you that day.",note:"-고 있을게요 = 'I'll be (doing)' — a warm, forward-looking close."},{id:"ko-b1-appointment-011",level:"B1",deck:"appointment",en:"to cancel (plans)",ko:"약속을 취소하다",roman:"yaksogeul chwisohada",exampleKo:"미안하지만 오늘 약속을 취소해야 할 것 같아요.",exampleEn:"I'm sorry, but I think I have to cancel today's plans.",note:"Softening with 미안하지만 ('I'm sorry, but') makes the cancel polite."},{id:"ko-b2-opinion-001",level:"B2",deck:"opinion",en:"In my opinion / From my point of view",ko:"제 생각에는",roman:"je saenggageneun",exampleKo:"제 생각에는 그 정책이 효과가 없을 것 같아요.",exampleEn:"In my opinion, that policy probably won't work.",note:"Polite, neutral way to open an opinion. Softer than 제가 보기에는."},{id:"ko-b2-opinion-002",level:"B2",deck:"opinion",en:"To be honest / Frankly",ko:"솔직히 말하면",roman:"soljiki malhamyeon",exampleKo:"솔직히 말하면 저는 그 의견에 반대해요.",exampleEn:"To be honest, I disagree with that view.",note:"Signals a candid, slightly stronger opinion is coming."},{id:"ko-b2-opinion-003",level:"B2",deck:"opinion",en:"I (partly) agree, but...",ko:"어느 정도 동의하지만",roman:"eoneu jeongdo donguihajiman",exampleKo:"어느 정도 동의하지만 현실적으로는 어려워요.",exampleEn:"I agree to some extent, but realistically it's difficult.",note:"Diplomatic partial agreement before raising a counterpoint."},{id:"ko-b2-opinion-004",level:"B2",deck:"opinion",en:"That makes sense, but...",ko:"일리가 있지만",roman:"illiga itjiman",exampleKo:"그 말도 일리가 있지만 부작용도 생각해야 해요.",exampleEn:"That point has merit, but we have to consider the side effects.",note:"일리가 있다 = 'has a point / is reasonable.' Common in debate."},{id:"ko-b2-opinion-005",level:"B2",deck:"opinion",en:"On the other hand",ko:"반면에",roman:"banmyeone",exampleKo:"비용은 줄지만 반면에 품질이 떨어질 수 있어요.",exampleEn:"Costs go down, but on the other hand quality may drop.",note:"Formal connector for contrasting two sides of an argument."},{id:"ko-b2-opinion-006",level:"B2",deck:"opinion",en:"The reason is that...",ko:"그 이유는",roman:"geu iyuneun",exampleKo:"제가 반대하는 그 이유는 비용 때문이에요.",exampleEn:"The reason I'm opposed is the cost.",note:"Introduces your grounds; often paired with ...때문이에요."},{id:"ko-b2-opinion-007",level:"B2",deck:"opinion",en:"I don't think so",ko:"그렇게 생각하지 않아요",roman:"geureoke saenggakaji anayo",exampleKo:"저는 그렇게 생각하지 않아요. 근거가 부족해요.",exampleEn:"I don't think so. There isn't enough evidence.",note:"Polite disagreement, softer than a flat 아니에요."},{id:"ko-b2-opinion-008",level:"B2",deck:"opinion",en:"Strictly speaking",ko:"엄밀히 따지면",roman:"eommilhi ttajimyeon",exampleKo:"엄밀히 따지면 그건 사실과 조금 달라요.",exampleEn:"Strictly speaking, that's a little different from the facts.",note:"Signals you're about to make a precise, careful distinction."},{id:"ko-b2-opinion-009",level:"B2",deck:"opinion",en:"That's a matter of opinion / It depends on the person",ko:"사람마다 다르죠",roman:"sarammada dareujyo",exampleKo:"취향은 사람마다 다르죠.",exampleEn:"Taste differs from person to person.",note:"Neutral way to acknowledge there's no single right answer."},{id:"ko-b2-opinion-010",level:"B2",deck:"opinion",en:"To sum up / In short",ko:"결론적으로",roman:"gyeollonjeogeuro",exampleKo:"결론적으로 저는 찬성하는 입장이에요.",exampleEn:"In conclusion, I'm in favor.",note:"Formal closer for wrapping up an argument. 입장 = stance."},{id:"ko-b2-opinion-011",level:"B2",deck:"opinion",en:"Needless to say / It goes without saying",ko:"말할 것도 없이",roman:"malhal geotdo eopsi",exampleKo:"말할 것도 없이 안전이 가장 중요해요.",exampleEn:"Needless to say, safety is the most important thing.",note:"Emphasizes something you treat as obvious or beyond dispute."},{id:"ko-b2-opinion-012",level:"B2",deck:"opinion",en:"If anything / Rather",ko:"오히려",roman:"ohiryeo",exampleKo:"규제가 오히려 시장을 망칠 수도 있어요.",exampleEn:"Regulation could, if anything, ruin the market.",note:"Flags a counter-intuitive turn — 'the opposite of what you'd expect.'"},{id:"ko-b2-news-001",level:"B2",deck:"news",en:"According to the report / news",ko:"보도에 따르면",roman:"bodoe ttareumyeon",exampleKo:"보도에 따르면 물가가 다시 올랐다고 해요.",exampleEn:"According to the report, prices have risen again.",note:"Standard journalistic phrase to cite a source. -다고 해요 = reported speech."},{id:"ko-b2-news-002",level:"B2",deck:"news",en:"Controversy / dispute",ko:"논란",roman:"nollan",exampleKo:"그 발언이 큰 논란을 일으켰어요.",exampleEn:"That remark sparked a big controversy.",note:"논란을 일으키다 = 'to spark controversy,' a very common collocation."},{id:"ko-b2-news-003",level:"B2",deck:"news",en:"Public opinion / sentiment",ko:"여론",roman:"yeoron",exampleKo:"여론이 정부에 등을 돌리고 있어요.",exampleEn:"Public opinion is turning against the government.",note:"등을 돌리다 = 'to turn one's back on.' Newsy idiom."},{id:"ko-b2-news-004",level:"B2",deck:"news",en:"Policy",ko:"정책",roman:"jeongchaek",exampleKo:"새 부동산 정책이 다음 달부터 시행돼요.",exampleEn:"The new real estate policy takes effect next month.",note:"시행되다 = 'to be put into effect / enforced.'"},{id:"ko-b2-news-005",level:"B2",deck:"news",en:"It is expected that... / forecast",ko:"전망이에요",roman:"jeonmangieyo",exampleKo:"올해 경제가 회복될 전망이에요.",exampleEn:"The economy is expected to recover this year.",note:"...ㄹ 전망이에요 = 'is forecast to.' Common in news writing."},{id:"ko-b2-news-006",level:"B2",deck:"news",en:"Pros and cons / mixed reactions",ko:"찬반이 갈리다",roman:"chanbani gallida",exampleKo:"이 법안을 두고 찬반이 갈리고 있어요.",exampleEn:"Opinions are split for and against this bill.",note:"찬반 = for/against; ...을 두고 = 'over (an issue).'"},{id:"ko-b2-news-007",level:"B2",deck:"news",en:"To be on the rise / increasing trend",ko:"증가하는 추세예요",roman:"jeunggahaneun chuseyeyo",exampleKo:"1인 가구가 꾸준히 증가하는 추세예요.",exampleEn:"Single-person households are steadily on the rise.",note:"추세 = trend; pairs with 증가/감소하는 to describe directions."},{id:"ko-b2-news-008",level:"B2",deck:"news",en:"Authorities / the relevant agency",ko:"당국",roman:"dangguk",exampleKo:"방역 당국이 새 지침을 발표했어요.",exampleEn:"The health authorities announced new guidelines.",note:"Formal news word for 'the authorities.' 발표하다 = to announce."},{id:"ko-b2-news-009",level:"B2",deck:"news",en:"Aftermath / repercussions",ko:"여파",roman:"yeopa",exampleKo:"경기 침체의 여파로 실업률이 올랐어요.",exampleEn:"Unemployment rose in the aftermath of the recession.",note:"...의 여파로 = 'as a repercussion of.' Often follows a crisis word."},{id:"ko-b2-news-010",level:"B2",deck:"news",en:"To raise an issue / point out a problem",ko:"문제를 제기하다",roman:"munjereul jegihada",exampleKo:"시민 단체가 안전 문제를 제기했어요.",exampleEn:"A civic group raised a safety concern.",note:"제기하다 = 'to raise (an objection, issue, lawsuit).' Formal."},{id:"ko-b2-news-011",level:"B2",deck:"news",en:"It turns out that... / it was revealed",ko:"밝혀졌어요",roman:"balkyeojyeosseoyo",exampleKo:"조사 결과 원인이 인재로 밝혀졌어요.",exampleEn:"The investigation revealed the cause was human error.",note:"밝혀지다 = 'to come to light.' 인재 = man-made disaster."},{id:"ko-b2-environment-001",level:"B2",deck:"environment",en:"Climate change",ko:"기후 변화",roman:"gihu byeonhwa",exampleKo:"기후 변화가 갈수록 심각해지고 있어요.",exampleEn:"Climate change is getting more serious over time.",note:"갈수록 = 'increasingly / as time goes on.'"},{id:"ko-b2-environment-002",level:"B2",deck:"environment",en:"Global warming",ko:"지구 온난화",roman:"jigu onnanhwa",exampleKo:"지구 온난화로 해수면이 상승하고 있어요.",exampleEn:"Sea levels are rising due to global warming.",note:"해수면 상승 = 'sea-level rise,' a set phrase in climate talk."},{id:"ko-b2-environment-003",level:"B2",deck:"environment",en:"Fine dust / air pollution",ko:"미세먼지",roman:"misemeonji",exampleKo:"오늘은 미세먼지가 심해서 마스크를 썼어요.",exampleEn:"The fine dust was bad today, so I wore a mask.",note:"A daily-life concern in Korea; 미세먼지 농도 = dust concentration level."},{id:"ko-b2-environment-004",level:"B2",deck:"environment",en:"Recycling / separating waste",ko:"분리수거",roman:"bullisugeo",exampleKo:"한국에서는 분리수거를 철저히 해야 해요.",exampleEn:"In Korea you have to sort your recycling thoroughly.",note:"분리수거 specifically = separating trash for recycling. 철저히 = thoroughly."},{id:"ko-b2-environment-005",level:"B2",deck:"environment",en:"Sustainable / eco-friendly",ko:"친환경",roman:"chinhwangyeong",exampleKo:"요즘 친환경 제품을 찾는 사람이 많아요.",exampleEn:"Lately many people look for eco-friendly products.",note:"친환경 attaches to nouns: 친환경 에너지, 친환경 포장 (packaging)."},{id:"ko-b2-environment-006",level:"B2",deck:"environment",en:"Carbon emissions",ko:"탄소 배출",roman:"tanso baechul",exampleKo:"정부가 탄소 배출을 줄이기로 했어요.",exampleEn:"The government decided to cut carbon emissions.",note:"탄소 배출량 = emission volume; 배출을 줄이다 = to reduce emissions."},{id:"ko-b2-environment-007",level:"B2",deck:"environment",en:"Single-use / disposable items",ko:"일회용품",roman:"ilhoeyongpum",exampleKo:"카페에서 일회용품 사용이 제한됐어요.",exampleEn:"The use of disposables was restricted in cafes.",note:"제한되다 = 'to be restricted.' A real Korean policy topic."},{id:"ko-b2-environment-008",level:"B2",deck:"environment",en:"Renewable energy",ko:"재생 에너지",roman:"jaesaeng eneoji",exampleKo:"태양광 같은 재생 에너지가 점점 늘고 있어요.",exampleEn:"Renewable energy like solar power is steadily growing.",note:"태양광 = solar; 풍력 = wind power. 점점 = gradually."},{id:"ko-b2-environment-009",level:"B2",deck:"environment",en:"Environmental pollution",ko:"환경 오염",roman:"hwangyeong oyeom",exampleKo:"플라스틱이 환경 오염의 주범이에요.",exampleEn:"Plastic is a main culprit of environmental pollution.",note:"주범 = 'main culprit,' a vivid but common figurative word."},{id:"ko-b2-environment-010",level:"B2",deck:"environment",en:"To practice / put into practice",ko:"실천하다",roman:"silcheonhada",exampleKo:"작은 일이라도 직접 실천하는 게 중요해요.",exampleEn:"It's important to actually practice it, even small things.",note:"실천 = turning intentions into action. Common in eco messaging."},{id:"ko-b2-environment-011",level:"B2",deck:"environment",en:"Conservation / protection",ko:"보호",roman:"boho",exampleKo:"멸종 위기 동물 보호가 시급해요.",exampleEn:"Protecting endangered animals is urgent.",note:"멸종 위기 = endangered; 시급하다 = to be urgent/pressing."},{id:"ko-b2-technology-001",level:"B2",deck:"technology",en:"Artificial intelligence (AI)",ko:"인공지능",roman:"ingongjineung",exampleKo:"인공지능이 우리 일자리를 바꾸고 있어요.",exampleEn:"AI is changing our jobs.",note:"Often shortened to the English-letter 'AI' in speech too."},{id:"ko-b2-technology-002",level:"B2",deck:"technology",en:"Personal data / privacy",ko:"개인정보",roman:"gaeinjeongbo",exampleKo:"개인정보 유출 사고가 또 일어났어요.",exampleEn:"There was another personal data leak.",note:"유출 = leak; 개인정보 보호 = data protection/privacy."},{id:"ko-b2-technology-003",level:"B2",deck:"technology",en:"To be convenient / handy",ko:"편리하다",roman:"pyeollihada",exampleKo:"모바일 결제가 정말 편리해졌어요.",exampleEn:"Mobile payments have become really convenient.",note:"편리하다 (convenient/useful) vs 편하다 (comfortable). Tech tends to use 편리하다."},{id:"ko-b2-technology-004",level:"B2",deck:"technology",en:"Side effect / downside",ko:"부작용",roman:"bujagyong",exampleKo:"기술 발전에는 부작용도 따라와요.",exampleEn:"Technological progress comes with downsides too.",note:"Originally 'medical side effect,' now used for any negative by-product."},{id:"ko-b2-technology-005",level:"B2",deck:"technology",en:"To depend on / be reliant on",ko:"의존하다",roman:"uijonhada",exampleKo:"우리는 스마트폰에 너무 의존하는 것 같아요.",exampleEn:"I think we rely on smartphones too much.",note:"...에 의존하다 = 'to depend on.' 의존도 = degree of dependence."},{id:"ko-b2-technology-006",level:"B2",deck:"technology",en:"To replace / take the place of",ko:"대체하다",roman:"daechehada",exampleKo:"기계가 사람을 완전히 대체하기는 어려워요.",exampleEn:"It's hard for machines to completely replace people.",note:"대체하다 = 'to substitute / replace.' 대체 인력 = replacement workforce."},{id:"ko-b2-technology-007",level:"B2",deck:"technology",en:"The digital divide / information gap",ko:"정보 격차",roman:"jeongbo gyeokcha",exampleKo:"노인층의 정보 격차가 점점 커지고 있어요.",exampleEn:"The information gap for older people keeps widening.",note:"격차 = gap/disparity; also 빈부 격차 = wealth gap."},{id:"ko-b2-technology-008",level:"B2",deck:"technology",en:"To innovate / cutting-edge",ko:"혁신적이다",roman:"hyeoksinjeogida",exampleKo:"그 회사의 기술은 정말 혁신적이에요.",exampleEn:"That company's technology is truly innovative.",note:"혁신 = innovation; 혁신적인 + noun = innovative."},{id:"ko-b2-technology-009",level:"B2",deck:"technology",en:"Fake news / misinformation",ko:"가짜 뉴스",roman:"gajja nyuseu",exampleKo:"온라인에 가짜 뉴스가 빠르게 퍼져요.",exampleEn:"Fake news spreads fast online.",note:"퍼지다 = to spread; 가짜 = fake (vs 진짜 = real)."},{id:"ko-b2-technology-010",level:"B2",deck:"technology",en:"Automation",ko:"자동화",roman:"jadonghwa",exampleKo:"공장 자동화로 생산성이 크게 올랐어요.",exampleEn:"Factory automation greatly raised productivity.",note:"-화 = '-ization' suffix: 자동화, 디지털화, 세계화 (globalization)."},{id:"ko-b2-technology-011",level:"B2",deck:"technology",en:"To keep up with / catch up to",ko:"따라가다",roman:"ttaragada",exampleKo:"기술 변화 속도를 따라가기가 벅차요.",exampleEn:"It's overwhelming to keep up with the pace of tech change.",note:"벅차다 = 'to be overwhelming / more than one can handle.'"},{id:"ko-b2-culture-001",level:"B2",deck:"culture",en:"Traditional culture",ko:"전통 문화",roman:"jeontong munhwa",exampleKo:"한국의 전통 문화에 관심이 많아요.",exampleEn:"I'm very interested in Korean traditional culture.",note:"전통 = tradition; 전통적인 + noun = traditional."},{id:"ko-b2-culture-002",level:"B2",deck:"culture",en:"Pop culture / mass culture",ko:"대중문화",roman:"daejung munhwa",exampleKo:"한국 대중문화가 전 세계로 퍼지고 있어요.",exampleEn:"Korean pop culture is spreading worldwide.",note:"대중 = the masses/public; the 'K' in K-pop is this 대중문화."},{id:"ko-b2-culture-003",level:"B2",deck:"culture",en:"To be moved / touched (emotionally)",ko:"감동을 받다",roman:"gamdongeul batda",exampleKo:"그 영화의 결말에 큰 감동을 받았어요.",exampleEn:"I was deeply moved by the film's ending.",note:"감동 = moving emotion; 감동적이다 = to be moving/touching."},{id:"ko-b2-culture-004",level:"B2",deck:"culture",en:"Exhibition",ko:"전시회",roman:"jeonsihoe",exampleKo:"주말에 사진 전시회를 보러 갔어요.",exampleEn:"I went to a photography exhibition over the weekend.",note:"전시 = display/exhibit; 전시회 = the exhibition event."},{id:"ko-b2-culture-005",level:"B2",deck:"culture",en:"Performance / show",ko:"공연",roman:"gongyeon",exampleKo:"어제 본 공연이 정말 인상 깊었어요.",exampleEn:"The performance I saw yesterday was really impressive.",note:"인상 깊다 = 'to leave a deep impression.' Great for reviews."},{id:"ko-b2-culture-006",level:"B2",deck:"culture",en:"Work (of art) / piece",ko:"작품",roman:"jakpum",exampleKo:"이 작품은 작가의 개성이 잘 드러나요.",exampleEn:"This piece clearly shows the artist's individuality.",note:"작품 = a created work (film, novel, painting); 작가 = creator/author."},{id:"ko-b2-culture-007",level:"B2",deck:"culture",en:"Taste / preference",ko:"취향",roman:"chwihyang",exampleKo:"음악 취향이 저랑 잘 맞네요.",exampleEn:"Your taste in music really matches mine.",note:"취향이 맞다 = 'tastes align.' 취향 저격 (slang) = right up my alley."},{id:"ko-b2-culture-008",level:"B2",deck:"culture",en:"To be worth (doing) / worthwhile",ko:"...ㄹ 만하다",roman:"...l manhada",exampleKo:"그 전시는 한번 가 볼 만해요.",exampleEn:"That exhibition is worth checking out.",note:"Verb stem + -ㄹ/을 만하다 = 'worth doing.' Very natural in recommendations."},{id:"ko-b2-culture-009",level:"B2",deck:"culture",en:"Trend / a craze",ko:"유행",roman:"yuhaeng",exampleKo:"복고풍이 다시 유행이에요.",exampleEn:"The retro style is in fashion again.",note:"유행하다 = to be trendy; 복고풍 = retro style."},{id:"ko-b2-culture-010",level:"B2",deck:"culture",en:"To have an eye for / be discerning",ko:"안목이 있다",roman:"anmogi itda",exampleKo:"그분은 예술에 안목이 있으세요.",exampleEn:"She has a discerning eye for art.",note:"안목 = a trained, perceptive eye for quality. A compliment."},{id:"ko-b2-culture-011",level:"B2",deck:"culture",en:"To be passed down / handed down",ko:"전해 내려오다",roman:"jeonhae naeryeooda",exampleKo:"이 풍습은 오래전부터 전해 내려왔어요.",exampleEn:"This custom has been handed down from long ago.",note:"풍습 = custom; used for traditions, legends, recipes across generations."},{id:"ko-c1-business-001",level:"C1",deck:"business",en:"to reach a consensus",ko:"합의를 도출하다",roman:"habuireul dochulhada",exampleKo:"양측은 긴 논의 끝에 합의를 도출했습니다.",exampleEn:"After lengthy discussion, both sides reached a consensus.",note:"합의 (agreement) + 도출하다 (to derive). Standard boardroom phrasing for arriving at an agreed outcome."},{id:"ko-c1-business-002",level:"C1",deck:"business",en:"to push ahead with a project",ko:"프로젝트를 추진하다",roman:"peurojekteureul chujinhada",exampleKo:"이사회 승인 후 본격적으로 사업을 추진할 예정입니다.",exampleEn:"We plan to push ahead with the project in earnest after board approval.",note:"추진하다 implies driving something forward with resources and intent, not just 'doing' it."},{id:"ko-c1-business-003",level:"C1",deck:"business",en:"to review the matter positively / favorably",ko:"긍정적으로 검토하다",roman:"geungjeongjeogeuro geomtohada",exampleKo:"제안하신 조건을 긍정적으로 검토하겠습니다.",exampleEn:"We will review the terms you proposed favorably.",note:"A polite, non-committal yes-ish phrase. In Korean business culture it signals openness without a firm promise."},{id:"ko-c1-business-004",level:"C1",deck:"business",en:"to take the lead / take the initiative",ko:"주도권을 잡다",roman:"judogwoneul japda",exampleKo:"협상에서 주도권을 잡으려면 자료가 탄탄해야 합니다.",exampleEn:"To take the lead in negotiations, your data must be solid.",note:"주도권 (initiative/control) + 잡다 (to grab). Used for seizing control of a deal or discussion."},{id:"ko-c1-business-005",level:"C1",deck:"business",en:"to weigh the pros and cons",ko:"득실을 따지다",roman:"deuksireul ttajida",exampleKo:"감정에 휘둘리지 말고 냉정하게 득실을 따져 봅시다.",exampleEn:"Let's not be swayed by emotion and coolly weigh the pros and cons.",note:"득실 = gains and losses (得失). 따지다 = to scrutinize/calculate. Common in strategic discussions."},{id:"ko-c1-business-006",level:"C1",deck:"business",en:"to defer / postpone a decision",ko:"결정을 보류하다",roman:"gyeoljeongeul boryuhada",exampleKo:"추가 검토가 필요해 최종 결정을 보류했습니다.",exampleEn:"We deferred the final decision because further review was needed.",note:"보류하다 (to hold/suspend) is the formal verb for tabling something pending more information."},{id:"ko-c1-business-007",level:"C1",deck:"business",en:"to secure a competitive edge",ko:"경쟁력을 확보하다",roman:"gyeongjaengnyeogeul hwakbohada",exampleKo:"기술 투자를 통해 시장 경쟁력을 확보해야 합니다.",exampleEn:"We must secure a competitive edge in the market through tech investment.",note:"경쟁력 (competitiveness) + 확보하다 (to secure). A staple in strategy and planning meetings."},{id:"ko-c1-business-008",level:"C1",deck:"business",en:"to set up a follow-up meeting",ko:"후속 미팅을 잡다",roman:"husok mitingeul japda",exampleKo:"세부 사항은 후속 미팅을 잡아 논의하시죠.",exampleEn:"Let's set up a follow-up meeting to discuss the details.",note:"후속 (follow-up, 後續). 잡다 here means 'to schedule'. A natural way to defer details politely."},{id:"ko-c1-business-009",level:"C1",deck:"business",en:"to streamline / cut down the budget",ko:"예산을 절감하다",roman:"yesaneul jeolgamhada",exampleKo:"불필요한 지출을 줄여 예산을 절감했습니다.",exampleEn:"We streamlined the budget by cutting unnecessary spending.",note:"절감하다 (to reduce/save, 節減) is more formal than 줄이다 and standard in financial reporting."},{id:"ko-c1-business-010",level:"C1",deck:"business",en:"to be held accountable / take responsibility",ko:"책임을 지다",roman:"chaegimeul jida",exampleKo:"이번 차질에 대해서는 제가 책임을 지겠습니다.",exampleEn:"I will take responsibility for this setback.",note:"책임을 지다 = to bear responsibility. Saying this signals accountability and is valued in Korean work culture."},{id:"ko-c1-business-011",level:"C1",deck:"business",en:"to bring up an agenda item / raise an issue",ko:"안건을 상정하다",roman:"angeoneul sangjeonghada",exampleKo:"다음 회의에 그 안건을 정식으로 상정하겠습니다.",exampleEn:"I will formally bring that item onto the agenda at the next meeting.",note:"안건 (agenda item, 案件) + 상정하다 (to table/submit, 上程). Formal meeting and committee language."},{id:"ko-c1-business-012",level:"C1",deck:"business",en:"to clearly define roles and responsibilities",ko:"역할과 책임을 분담하다",roman:"yeokalgwa chaegimeul bundamhada",exampleKo:"혼선을 막으려면 팀원 간 역할과 책임을 분담해야 합니다.",exampleEn:"To avoid confusion, we must clearly divide roles and responsibilities among the team.",note:"분담하다 (to share/divide a burden, 分擔). Used when assigning ownership across a team."},{id:"ko-c1-society-001",level:"C1",deck:"society",en:"the widening gap between rich and poor",ko:"빈부 격차",roman:"binbu gyeokcha",exampleKo:"빈부 격차가 심화되면서 사회 불만이 커지고 있습니다.",exampleEn:"As the wealth gap widens, social discontent is growing.",note:"빈부 (rich and poor, 貧富) + 격차 (gap, 隔差). A core term in any discussion of inequality."},{id:"ko-c1-society-002",level:"C1",deck:"society",en:"an aging society",ko:"고령화 사회",roman:"goryeonghwa sahoe",exampleKo:"고령화 사회로 접어들면서 연금 문제가 대두되고 있습니다.",exampleEn:"As we enter an aging society, the pension issue is coming to the fore.",note:"고령화 (aging, 高齡化). Korea's rapid demographic shift makes this a frequent headline term."},{id:"ko-c1-society-003",level:"C1",deck:"society",en:"to come to the fore / become a major issue",ko:"대두되다",roman:"daedudoeda",exampleKo:"청년 실업 문제가 사회적 화두로 대두되었습니다.",exampleEn:"Youth unemployment has emerged as a major social issue.",note:"대두되다 (to rise to prominence, 擡頭) is used for issues newly gaining attention. More formal than 생기다."},{id:"ko-c1-society-004",level:"C1",deck:"society",en:"to bridge / resolve a generational gap",ko:"세대 갈등을 해소하다",roman:"sedae galdeungeul haesohada",exampleKo:"세대 갈등을 해소하려면 서로의 입장을 이해해야 합니다.",exampleEn:"To resolve the generational conflict, each side must understand the other's position.",note:"세대 갈등 (generational conflict). 해소하다 (to dissolve/relieve, 解消) pairs with conflicts and stress."},{id:"ko-c1-society-005",level:"C1",deck:"society",en:"to strengthen the social safety net",ko:"사회 안전망을 강화하다",roman:"sahoe anjeonmangeul ganghwahada",exampleKo:"취약 계층을 위해 사회 안전망을 강화할 필요가 있습니다.",exampleEn:"We need to strengthen the social safety net for vulnerable groups.",note:"안전망 (safety net) is a direct calque. 취약 계층 (vulnerable groups) often appears alongside it."},{id:"ko-c1-society-006",level:"C1",deck:"society",en:"to gather / build public consensus",ko:"공감대를 형성하다",roman:"gonggamdaereul hyeongseonghada",exampleKo:"정책을 추진하기 전에 사회적 공감대를 형성해야 합니다.",exampleEn:"Before pushing a policy, we must build public consensus.",note:"공감대 (shared empathy/common ground) + 형성하다 (to form, 形成). Key for policy and PR contexts."},{id:"ko-c1-society-007",level:"C1",deck:"society",en:"the polarization of public opinion",ko:"여론의 양극화",roman:"yeoronui yanggeukhwa",exampleKo:"이번 사안을 두고 여론의 양극화가 뚜렷합니다.",exampleEn:"Public opinion is sharply polarized over this issue.",note:"양극화 (polarization, 兩極化) applies to opinion, wealth, and politics alike. Very common in op-eds."},{id:"ko-c1-society-008",level:"C1",deck:"society",en:"to take root as a social norm / settle in",ko:"사회적으로 자리 잡다",roman:"sahoejeogeuro jari japda",exampleKo:"재택근무가 하나의 문화로 사회적으로 자리 잡았습니다.",exampleEn:"Remote work has taken root as a cultural norm in society.",note:"자리 잡다 (to settle into place) describes a practice becoming established and accepted."},{id:"ko-c1-society-009",level:"C1",deck:"society",en:"to be marginalized / pushed to the fringes",ko:"소외되다",roman:"sooedoeda",exampleKo:"기술 발전 속에서 노년층이 소외되지 않도록 해야 합니다.",exampleEn:"We must ensure the elderly are not marginalized amid technological progress.",note:"소외되다 (to be alienated/excluded, 疏外). Central to discussions of the digital divide and inequality."},{id:"ko-c1-society-010",level:"C1",deck:"society",en:"a pending issue / unresolved task",ko:"현안",roman:"hyeonan",exampleKo:"주거 문제는 정부가 시급히 풀어야 할 현안입니다.",exampleEn:"Housing is a pressing issue the government must urgently address.",note:"현안 (current pending matter, 懸案). Sounds formal and journalistic; common in news and policy."},{id:"ko-c1-society-011",level:"C1",deck:"society",en:"to raise public awareness",ko:"인식을 제고하다",roman:"insigeul jegohada",exampleKo:"환경 보호에 대한 시민들의 인식을 제고해야 합니다.",exampleEn:"We must raise citizens' awareness of environmental protection.",note:"제고하다 (to enhance/raise, 提高) is a formal alternative to 높이다, common in campaigns and reports."},{id:"ko-c1-abstract-001",level:"C1",deck:"abstract",en:"based on the premise that ~",ko:"~라는 전제하에",roman:"~raneun jeonjeha-e",exampleKo:"모두가 동의한다는 전제하에 논의를 진행하겠습니다.",exampleEn:"I'll proceed on the premise that everyone agrees.",note:"전제 (premise, 前提) + 하에 (under). Sets up a conditional assumption for an argument."},{id:"ko-c1-abstract-002",level:"C1",deck:"abstract",en:"to be logically coherent / consistent",ko:"논리적으로 일관되다",roman:"nollijeogeuro ilgwandoeda",exampleKo:"그의 주장은 처음부터 끝까지 논리적으로 일관됩니다.",exampleEn:"His argument is logically consistent from start to finish.",note:"일관되다 (to be consistent, 一貫). Praising or critiquing the internal coherence of an argument."},{id:"ko-c1-abstract-003",level:"C1",deck:"abstract",en:"to back up a claim with evidence",ko:"근거를 뒷받침하다",roman:"geun-georeul dwitbatchimhada",exampleKo:"주장을 뒷받침할 객관적인 근거가 필요합니다.",exampleEn:"We need objective evidence to back up the claim.",note:"뒷받침하다 (to support/underpin) pairs naturally with 근거 (grounds) and 주장 (claim)."},{id:"ko-c1-abstract-004",level:"C1",deck:"abstract",en:"to draw a conclusion",ko:"결론을 도출하다",roman:"gyeollon-eul dochulhada",exampleKo:"데이터를 종합해 합리적인 결론을 도출했습니다.",exampleEn:"We drew a reasonable conclusion by synthesizing the data.",note:"도출하다 (to derive, 導出) is the formal verb for reaching conclusions or results from premises."},{id:"ko-c1-abstract-005",level:"C1",deck:"abstract",en:"to put it the other way around / conversely",ko:"역으로 말하면",roman:"yeogeuro malhamyeon",exampleKo:"역으로 말하면, 규제가 없으면 시장이 혼란해진다는 뜻입니다.",exampleEn:"Conversely, it means the market becomes chaotic without regulation.",note:"역으로 (in reverse, 逆). A useful connective for reframing or testing the inverse of a point."},{id:"ko-c1-abstract-006",level:"C1",deck:"abstract",en:"there is room for debate / it's open to dispute",ko:"논란의 여지가 있다",roman:"nollanui yeojiga itda",exampleKo:"그 해석은 여전히 논란의 여지가 있습니다.",exampleEn:"That interpretation is still open to debate.",note:"여지 (room/leeway, 餘地) + 있다. A measured way to flag that a claim isn't settled."},{id:"ko-c1-abstract-007",level:"C1",deck:"abstract",en:"to view it from a different angle",ko:"다른 관점에서 보다",roman:"dareun gwanjeomeseo boda",exampleKo:"같은 현상도 다른 관점에서 보면 해석이 달라집니다.",exampleEn:"Even the same phenomenon yields a different reading when viewed from another angle.",note:"관점 (viewpoint, 觀點). Essential for introducing an alternative interpretation in discussion."},{id:"ko-c1-abstract-008",level:"C1",deck:"abstract",en:"to be a logical leap / a stretch",ko:"비약이 심하다",roman:"biyagi simhada",exampleKo:"전제에서 결론으로 가는 과정에 비약이 심합니다.",exampleEn:"There's a serious logical leap from the premise to the conclusion.",note:"비약 (a leap, 飛躍) here is a fallacy of jumping to a conclusion. A precise critique of weak reasoning."},{id:"ko-c1-abstract-009",level:"C1",deck:"abstract",en:"to be a matter of perspective / it depends how you see it",ko:"보기 나름이다",roman:"bogi nareumida",exampleKo:"성공인지 실패인지는 보기 나름입니다.",exampleEn:"Whether it's a success or a failure depends on how you look at it.",note:"나름이다 = 'depends on'. A natural, idiomatic way to say something is relative or subjective."},{id:"ko-c1-abstract-010",level:"C1",deck:"abstract",en:"in essence / at its core",ko:"본질적으로",roman:"bonjiljeogeuro",exampleKo:"이 문제는 본질적으로 신뢰의 문제입니다.",exampleEn:"At its core, this is a question of trust.",note:"본질 (essence, 本質). Use to cut past surface details to the fundamental point."},{id:"ko-c1-abstract-011",level:"C1",deck:"abstract",en:"to take ~ for granted / regard as a given",ko:"당연시하다",roman:"dangyeonsihada",exampleKo:"우리는 표현의 자유를 너무 당연시하는 경향이 있습니다.",exampleEn:"We tend to take freedom of expression too much for granted.",note:"당연시하다 (to treat as obvious, 當然視) flags an unexamined assumption worth questioning."},{id:"ko-c1-media-001",level:"C1",deck:"media",en:"to report in detail / cover extensively",ko:"상세히 보도하다",roman:"sangsehi bodohada",exampleKo:"언론은 사건의 경위를 상세히 보도했습니다.",exampleEn:"The media reported the circumstances of the incident in detail.",note:"보도하다 (to report, 報道) is the journalistic verb, distinct from everyday 알리다 (to inform)."},{id:"ko-c1-media-002",level:"C1",deck:"media",en:"to spread / circulate (rumors, information)",ko:"유포되다",roman:"yupodoeda",exampleKo:"확인되지 않은 정보가 온라인에 빠르게 유포되었습니다.",exampleEn:"Unverified information spread rapidly online.",note:"유포되다 (to be disseminated, 流布) often carries a negative nuance — rumors or misinformation."},{id:"ko-c1-media-003",level:"C1",deck:"media",en:"to gauge / read public opinion",ko:"여론을 수렴하다",roman:"yeoroneul suryeomhada",exampleKo:"정부는 공청회를 열어 여론을 수렴했습니다.",exampleEn:"The government held a public hearing to gather public opinion.",note:"수렴하다 (to collect/converge, 收斂) means gathering diverse views toward a decision. Formal register."},{id:"ko-c1-media-004",level:"C1",deck:"media",en:"fake news / false reporting",ko:"허위 보도",roman:"heowi bodo",exampleKo:"허위 보도로 인한 피해가 갈수록 심각해지고 있습니다.",exampleEn:"Damage from false reporting is becoming increasingly serious.",note:"허위 (false, 虛僞) + 보도 (report). The standard term in legal and media-ethics discussions."},{id:"ko-c1-media-005",level:"C1",deck:"media",en:"to frame an issue a certain way",ko:"프레임을 씌우다",roman:"peureimeul ssiuda",exampleKo:"특정 진영이 그 사건에 정치적 프레임을 씌웠습니다.",exampleEn:"A particular faction framed the incident politically.",note:"프레임을 씌우다 = to impose a frame/narrative. 씌우다 (to put on/over) carries a manipulative nuance."},{id:"ko-c1-media-006",level:"C1",deck:"media",en:"to be reported sensationally / blown up",ko:"자극적으로 다루다",roman:"jageukjeogeuro daruda",exampleKo:"일부 매체가 사건을 지나치게 자극적으로 다뤘습니다.",exampleEn:"Some outlets covered the incident far too sensationally.",note:"자극적 (sensational/provocative, 刺戟的) + 다루다 (to handle/treat). A critique of tabloid-style coverage."},{id:"ko-c1-media-007",level:"C1",deck:"media",en:"to shape / foster public opinion",ko:"여론을 조성하다",roman:"yeoroneul josonghada",exampleKo:"광고는 특정 제품에 우호적인 여론을 조성합니다.",exampleEn:"Advertising fosters favorable public opinion toward certain products.",note:"조성하다 (to create/build up, 造成). Used for deliberately shaping a mood or sentiment."},{id:"ko-c1-media-008",level:"C1",deck:"media",en:"to verify the facts / fact-check",ko:"사실 관계를 확인하다",roman:"sasil gwangyereul hwaginhada",exampleKo:"보도 전에 반드시 사실 관계를 확인해야 합니다.",exampleEn:"The facts must be verified before reporting.",note:"사실 관계 (the facts / factual relations) is the set phrase journalists use for what needs checking."},{id:"ko-c1-media-009",level:"C1",deck:"media",en:"to be in the spotlight / draw attention",ko:"이목을 끌다",roman:"imogeul kkeulda",exampleKo:"그 발언은 단숨에 대중의 이목을 끌었습니다.",exampleEn:"That remark instantly drew the public's attention.",note:"이목 (eyes and ears → attention, 耳目) + 끌다 (to draw). More literary than 관심을 끌다."},{id:"ko-c1-media-010",level:"C1",deck:"media",en:"to correct / issue a correction to a report",ko:"보도를 정정하다",roman:"bodoreul jeongjeonghada",exampleKo:"오류가 드러나자 방송사는 즉시 보도를 정정했습니다.",exampleEn:"Once the error came to light, the broadcaster immediately corrected the report.",note:"정정하다 (to correct/rectify, 訂正) is the formal verb for issuing a correction."},{id:"ko-c1-media-011",level:"C1",deck:"media",en:"to take ~ at face value / accept uncritically",ko:"곧이곧대로 받아들이다",roman:"gojigotdaero badadeurida",exampleKo:"기사를 곧이곧대로 받아들이기보다 출처를 따져야 합니다.",exampleEn:"Rather than taking an article at face value, you should examine the source.",note:"곧이곧대로 = literally/uncritically. A native idiom warning against naive acceptance of information."},{id:"ko-c2-academic-001",level:"C2",deck:"academic",en:"to take ~ as a premise / presuppose",ko:"전제하다",roman:"jeonjehada",exampleKo:"이 논의는 시장이 합리적이라는 가정을 전제합니다.",exampleEn:"This discussion presupposes that the market is rational.",note:"Academic staple for stating an underlying assumption before an argument."},{id:"ko-c2-academic-002",level:"C2",deck:"academic",en:"to substantiate / demonstrate (with evidence)",ko:"입증하다",roman:"ipjeunghada",exampleKo:"연구진은 가설을 실험으로 입증했습니다.",exampleEn:"The researchers substantiated the hypothesis through experiment.",note:"Stronger than 보여주다 — implies proof backed by rigorous evidence."},{id:"ko-c2-academic-003",level:"C2",deck:"academic",en:"to be at odds with / contradict",ko:"상충하다",roman:"sangchunghada",exampleKo:"두 이론의 결론은 서로 상충합니다.",exampleEn:"The conclusions of the two theories are at odds with each other.",note:"Formal way to say two findings or interests conflict."},{id:"ko-c2-academic-004",level:"C2",deck:"academic",en:"consideration / point worth weighing",ko:"고려 사항",roman:"goryeo sahang",exampleKo:"정책 설계에서 형평성은 핵심 고려 사항입니다.",exampleEn:"Equity is a key consideration in policy design.",note:"Set phrase in reports for 'factors to take into account'."},{id:"ko-c2-academic-005",level:"C2",deck:"academic",en:"in this regard / on this point",ko:"이러한 측면에서",roman:"ireohan cheungmyeoneseo",exampleKo:"이러한 측면에서 기존 연구는 한계가 분명합니다.",exampleEn:"In this regard, the existing research has clear limitations.",note:"Smooth connective to pivot a paragraph in academic prose."},{id:"ko-c2-academic-006",level:"C2",deck:"academic",en:"to be interpreted / read as",ko:"해석되다",roman:"haeseokdoeda",exampleKo:"이 결과는 두 가지로 해석될 수 있습니다.",exampleEn:"This result can be interpreted in two ways.",note:"Passive form preferred in objective academic writing."},{id:"ko-c2-academic-007",level:"C2",deck:"academic",en:"by extension / furthermore",ko:"나아가",roman:"naaga",exampleKo:"나아가 이 발견은 교육 정책에도 시사점을 줍니다.",exampleEn:"Furthermore, this finding has implications for education policy.",note:"Elevated 'moreover'; signals the argument is broadening in scope."},{id:"ko-c2-academic-008",level:"C2",deck:"academic",en:"implication / suggested meaning",ko:"시사점",roman:"sisajeom",exampleKo:"이 연구가 주는 시사점은 적지 않습니다.",exampleEn:"The implications of this study are considerable.",note:"Common in conclusions: the 'so what' takeaway of a study."},{id:"ko-c2-academic-009",level:"C2",deck:"academic",en:"to be limited to / confined to",ko:"국한되다",roman:"gukhandoeda",exampleKo:"이 현상은 도시 지역에 국한되지 않습니다.",exampleEn:"This phenomenon is not confined to urban areas.",note:"Formal; often used in the negative to claim broad applicability."},{id:"ko-c2-academic-010",level:"C2",deck:"academic",en:"to originate from / stem from",ko:"기인하다",roman:"giinhada",exampleKo:"그 차이는 표본의 편향에 기인합니다.",exampleEn:"The difference stems from sampling bias.",note:"'기인하다 + 에' = to originate from a cause; very academic."},{id:"ko-c2-academic-011",level:"C2",deck:"academic",en:"to investigate and clarify",ko:"규명하다",roman:"gyumyeonghada",exampleKo:"이 논문은 원인과 결과의 관계를 규명합니다.",exampleEn:"This paper clarifies the relationship between cause and effect.",note:"To investigate and establish a fact clearly; stronger than 밝히다."},{id:"ko-c2-idioms-001",level:"C2",deck:"idioms",en:"self-contradiction (lit. 'spear and shield')",ko:"모순",roman:"mosun",exampleKo:"그 주장은 그 자체로 모순입니다.",exampleEn:"That claim is a contradiction in itself.",note:"From a parable of a vendor selling an all-piercing spear and an impenetrable shield."},{id:"ko-c2-idioms-002",level:"C2",deck:"idioms",en:"killing two birds with one stone (one stone, two birds)",ko:"일석이조",roman:"ilseogijo",exampleKo:"재택근무는 시간도 아끼고 건강도 챙기니 일석이조예요.",exampleEn:"Working from home saves time and improves health — two birds with one stone.",note:"Four-character idiom; the everyday native equivalent is 꿩 먹고 알 먹기."},{id:"ko-c2-idioms-003",level:"C2",deck:"idioms",en:"going to great lengths through hardship (enduring trials)",ko:"고진감래",roman:"gojingamnae",exampleKo:"고진감래라더니, 오랜 고생 끝에 결실을 맺었네요.",exampleEn:"As they say, no pain no gain — long hardship finally bore fruit.",note:"Lit. 'bitterness ends, sweetness comes' — Korean 'no pain, no gain'."},{id:"ko-c2-idioms-004",level:"C2",deck:"idioms",en:"even monkeys fall from trees (anyone can slip up)",ko:"원숭이도 나무에서 떨어진다",roman:"wonsungido namueseo tteoreojinda",exampleKo:"원숭이도 나무에서 떨어진다고, 전문가도 실수할 때가 있죠.",exampleEn:"Even monkeys fall from trees — even experts make mistakes.",note:"Native proverb to console someone skilled who erred."},{id:"ko-c2-idioms-005",level:"C2",deck:"idioms",en:"a frog in a well (a narrow, limited worldview)",ko:"우물 안 개구리",roman:"umul an gaeguri",exampleKo:"해외에 나가 보니 제가 우물 안 개구리였더라고요.",exampleEn:"Going abroad, I realized I'd been a frog in a well.",note:"Describes someone unaware of the wider world; mildly self-deprecating."},{id:"ko-c2-idioms-006",level:"C2",deck:"idioms",en:"to add insult to injury (lit. 'salt on a wound')",ko:"엎친 데 덮친 격",roman:"eopchin de deopchin gyeok",exampleKo:"차도 고장 났는데 비까지 오니 엎친 데 덮친 격이네요.",exampleEn:"The car broke down and then it rained — when it rains, it pours.",note:"Native idiom for misfortunes piling up at once."},{id:"ko-c2-idioms-007",level:"C2",deck:"idioms",en:"out of the blue / a bolt from clear sky",ko:"청천벽력",roman:"cheongcheonbyeongnyeok",exampleKo:"해고 통보는 그야말로 청천벽력이었습니다.",exampleEn:"The layoff notice was a complete bolt from the blue.",note:"Lit. 'thunderbolt from a clear sky' — a sudden, shocking calamity."},{id:"ko-c2-idioms-008",level:"C2",deck:"idioms",en:"consistent from start to finish (one principle throughout)",ko:"시종일관",roman:"sijongilgwan",exampleKo:"그는 시종일관 침착한 태도를 유지했습니다.",exampleEn:"He maintained a calm attitude from start to finish.",note:"Praises unwavering consistency; common in formal description."},{id:"ko-c2-idioms-009",level:"C2",deck:"idioms",en:"speaking in a roundabout, evasive way (beating around the bush)",ko:"변죽을 울리다",roman:"byeonjugeul ullida",exampleKo:"변죽만 울리지 말고 본론을 말씀해 주세요.",exampleEn:"Stop beating around the bush and get to the point.",note:"Native idiom; literally 'to ring the rim (not the center) of a gong'."},{id:"ko-c2-idioms-010",level:"C2",deck:"idioms",en:"mutually beneficial; both sides win-win",ko:"상부상조",roman:"sangbusangjo",exampleKo:"두 회사는 상부상조하며 함께 성장했습니다.",exampleEn:"The two firms grew together by helping each other.",note:"Four-character idiom emphasizing reciprocal aid."},{id:"ko-c2-idioms-011",level:"C2",deck:"idioms",en:"to make a mountain out of a molehill (exaggerate)",ko:"침소봉대",roman:"chimsobongdae",exampleKo:"작은 실수를 침소봉대해서 말할 필요는 없습니다.",exampleEn:"There's no need to blow a small mistake out of proportion.",note:"Lit. 'make a needle into a club' — to overstate something trivial."},{id:"ko-c2-idioms-012",level:"C2",deck:"idioms",en:"a blessing in disguise / fortune is unpredictable",ko:"전화위복",roman:"jeonhwawibok",exampleKo:"이번 실패가 전화위복이 되어 더 좋은 기회를 얻었어요.",exampleEn:"This failure turned out to be a blessing in disguise, opening a better door.",note:"Lit. 'turning misfortune into fortune'; very common encouragement."},{id:"ko-c2-nuance-001",level:"C2",deck:"nuance",en:"by all means / no matter what (insistent)",ko:"기어이",roman:"gieoi",exampleKo:"그는 기어이 정상에 오르고야 말았다.",exampleEn:"He made it to the summit no matter what.",note:"Implies stubborn persistence against odds; stronger than 결국."},{id:"ko-c2-nuance-002",level:"C2",deck:"nuance",en:"in the end / after all that (resigned)",ko:"끝내",roman:"kkeunnae",exampleKo:"그는 끝내 대답하지 않았다.",exampleEn:"In the end, he never answered.",note:"Often carries a tinge of regret or finality, unlike neutral 결국."},{id:"ko-c2-nuance-003",level:"C2",deck:"nuance",en:"supposedly / I hear that (hearsay, reported)",ko:"-다나 봐요",roman:"-dana bwayo",exampleKo:"그 식당이 곧 문을 닫는다나 봐요.",exampleEn:"I hear that restaurant is closing soon, apparently.",note:"Adds a casual 'so they say, but who knows' distance to hearsay."},{id:"ko-c2-nuance-004",level:"C2",deck:"nuance",en:"rather / on the contrary (contrary to expectation)",ko:"오히려",roman:"ohiryeo",exampleKo:"사과했더니 오히려 화를 더 냈어요.",exampleEn:"When I apologized, he got even angrier instead.",note:"Flags a result opposite to what you'd reasonably expect."},{id:"ko-c2-nuance-005",level:"C2",deck:"nuance",en:"after all / when it comes down to it",ko:"어차피",roman:"eochapi",exampleKo:"어차피 늦었으니 천천히 갑시다.",exampleEn:"We're late anyway, so let's take our time.",note:"Resigned 'since the outcome is fixed regardless'; very colloquial."},{id:"ko-c2-nuance-006",level:"C2",deck:"nuance",en:"somehow / for some reason (vague unease)",ko:"왠지",roman:"waenji",exampleKo:"왠지 오늘은 일이 잘 풀릴 것 같아요.",exampleEn:"Somehow I feel things will go well today.",note:"A gut feeling you can't fully explain; note 왠지 vs. 웬일 spelling."},{id:"ko-c2-nuance-007",level:"C2",deck:"nuance",en:"as expected / sure enough (confirming a hunch)",ko:"역시",roman:"yeoksi",exampleKo:"역시 네 말이 맞았어.",exampleEn:"Sure enough, you were right.",note:"Confirms what you suspected; also a warm compliment ('I knew you'd deliver')."},{id:"ko-c2-nuance-008",level:"C2",deck:"nuance",en:"if anything / relatively speaking",ko:"차라리",roman:"charari",exampleKo:"이럴 바엔 차라리 안 하는 게 나아요.",exampleEn:"If it's going to be like this, I'd rather not do it at all.",note:"Picks the lesser evil among unsatisfactory options."},{id:"ko-c2-nuance-009",level:"C2",deck:"nuance",en:"needless to say / it goes without saying",ko:"두말할 나위 없이",roman:"dumalhal nawi eopsi",exampleKo:"두말할 나위 없이 그가 최고의 후보입니다.",exampleEn:"Needless to say, he is the best candidate.",note:"Elevated set phrase; 나위 (room/need) appears almost only here."},{id:"ko-c2-nuance-010",level:"C2",deck:"nuance",en:"barely / only just (a hair's breadth)",ko:"가까스로",roman:"gakkaseuro",exampleKo:"막차를 가까스로 탔어요.",exampleEn:"I barely caught the last train.",note:"Emphasizes a narrow, effortful margin; stronger than 겨우."},{id:"ko-c2-nuance-011",level:"C2",deck:"nuance",en:"albeit belatedly / however late",ko:"뒤늦게나마",roman:"dwineutgenama",exampleKo:"뒤늦게나마 사과의 말씀을 드립니다.",exampleEn:"Belated as it is, I offer my apology.",note:"-나마 = 'even if only'; softens that the action comes too late."},{id:"ko-c2-nuance-012",level:"C2",deck:"nuance",en:"to a fault / excessively (in a way that backfires)",ko:"지나치게",roman:"jinachige",exampleKo:"그는 지나치게 신중해서 기회를 놓치곤 해요.",exampleEn:"He is cautious to a fault and often misses opportunities.",note:"Implies an otherwise good trait pushed past the healthy limit."},{id:"ko-c2-formal-001",level:"C2",deck:"formal",en:"to express deep gratitude (humble, formal)",ko:"심심한 감사를 드립니다",roman:"simsimhan gamsareul deurimnida",exampleKo:"참석해 주신 여러분께 심심한 감사를 드립니다.",exampleEn:"I extend my profound gratitude to everyone who attended.",note:"심심하다 here = 'deep/heartfelt' (深甚), not 'bored' — a classic formal phrase."},{id:"ko-c2-formal-002",level:"C2",deck:"formal",en:"to ask for your generous understanding",ko:"너른 양해를 부탁드립니다",roman:"neoreun yanghaereul butakdeurimnida",exampleKo:"준비 과정의 미흡함에 너른 양해를 부탁드립니다.",exampleEn:"We ask for your generous understanding of any shortcomings.",note:"Standard apology-and-request line in official notices and speeches."},{id:"ko-c2-formal-003",level:"C2",deck:"formal",en:"to humbly state / submit (in writing)",ko:"삼가 아룁니다",roman:"samga aryumnida",exampleKo:"고인의 명복을 빌며 삼가 아룁니다.",exampleEn:"Praying for the repose of the deceased, I humbly write these words.",note:"삼가 = 'respectfully/humbly'; very ceremonial, used in eulogies and formal letters."},{id:"ko-c2-formal-004",level:"C2",deck:"formal",en:"to take this opportunity to (formal preamble)",ko:"이 자리를 빌려",roman:"i jarireul billyeo",exampleKo:"이 자리를 빌려 그동안의 노고에 감사드립니다.",exampleEn:"I would like to take this opportunity to thank you for your hard work.",note:"Set opener in speeches to insert a word of thanks; note 빌려, not 빌어."},{id:"ko-c2-formal-005",level:"C2",deck:"formal",en:"henceforth / from this point on (formal)",ko:"향후",roman:"hyanghu",exampleKo:"향후 계획에 대해 말씀드리겠습니다.",exampleEn:"I will now speak about our plans going forward.",note:"Sino-Korean 'henceforth'; crisper and more official than 앞으로."},{id:"ko-c2-formal-006",level:"C2",deck:"formal",en:"to come to a conclusion / draw to a close",ko:"갈음하다",roman:"gareumhada",exampleKo:"이것으로 인사말을 갈음하고자 합니다.",exampleEn:"With this, I would like to conclude my opening remarks.",note:"'To substitute / let one thing stand in for another'; signature speech-closing verb."},{id:"ko-c2-formal-007",level:"C2",deck:"formal",en:"to revere / hold in deep respect",ko:"존경해 마지않다",roman:"jongyeonghae majianta",exampleKo:"제가 존경해 마지않는 선생님을 모셨습니다.",exampleEn:"I have invited a teacher whom I deeply revere.",note:"-아/어 마지않다 = 'cannot help but ~'; an emphatic, literary intensifier."},{id:"ko-c2-formal-008",level:"C2",deck:"formal",en:"to wish for your continued prosperity",ko:"무궁한 발전을 기원합니다",roman:"mugunghan baljeoneul giwonhamnida",exampleKo:"귀사의 무궁한 발전을 기원합니다.",exampleEn:"We wish your company everlasting prosperity.",note:"Boilerplate closing for business letters and congratulatory addresses."},{id:"ko-c2-formal-009",level:"C2",deck:"formal",en:"to be deeply moved / overcome with emotion",ko:"감개무량하다",roman:"gamgaemuryanghada",exampleKo:"이 상을 받게 되어 감개무량합니다.",exampleEn:"I am overwhelmed with emotion to receive this award.",note:"Four-character idiom for being flooded with deep feeling; common in acceptance speeches."},{id:"ko-c2-formal-010",level:"C2",deck:"formal",en:"to be unworthy of such praise (humble)",ko:"과분한 말씀입니다",roman:"gwabunhan malsseumimnida",exampleKo:"그렇게 칭찬해 주시니 과분한 말씀입니다.",exampleEn:"Such praise is more than I deserve.",note:"Humble deflection of a compliment; 과분하다 = 'excessive for one's station'."},{id:"ko-c2-formal-011",level:"C2",deck:"formal",en:"to request your kind attention / cooperation",ko:"협조를 당부드립니다",roman:"hyeopjoreul dangbudeurimnida",exampleKo:"원활한 진행을 위해 여러분의 협조를 당부드립니다.",exampleEn:"We earnestly request your cooperation for a smooth proceeding.",note:"당부하다 = 'to earnestly request/urge'; weightier than 부탁하다."}].filter(e=>{let a=e.ko.replace(/[.,!?;:'"\s]/g,"").trim();return!o.has(a)&&(o.add(a),!0)});e.s(["ALL_CARDS_KO",0,a,"ALL_DECKS_KO",0,[{id:"greetings",level:"A1",title:{ko:"인사",en:"Greetings"},description:{ko:"기본 인사와 작별",en:"Hellos and goodbyes"},order:1,icon:"Hand"},{id:"self-intro",level:"A1",title:{ko:"자기소개",en:"Introducing Yourself"},description:{ko:"이름·출신·직업·나이",en:"Name, origin, job, and age"},order:2,icon:"UserRound"},{id:"numbers",level:"A1",title:{ko:"숫자",en:"Numbers"},description:{ko:"하나~열, 십~백, 수량 세기",en:"Counting and quantities"},order:3,icon:"Hash"},{id:"food",level:"A1",title:{ko:"음식·식당",en:"Food & Dining"},description:{ko:"주문·맛·계산",en:"Ordering, taste, and paying"},order:4,icon:"Utensils"},{id:"family",level:"A1",title:{ko:"가족",en:"Family"},description:{ko:"가족 호칭·소개",en:"Family members and introductions"},order:5,icon:"Users"},{id:"time-date",level:"A2",title:{ko:"시간·날짜",en:"Time & Date"},description:{ko:"시간, 요일, 날짜 말하기",en:"Telling time, days, and dates"},order:1,icon:"Clock"},{id:"shopping",level:"A2",title:{ko:"쇼핑",en:"Shopping"},description:{ko:"가게에서 사고 묻기",en:"Buying and asking in stores"},order:2,icon:"ShoppingBag"},{id:"transport",level:"A2",title:{ko:"교통",en:"Transportation"},description:{ko:"버스, 지하철, 길 찾기",en:"Buses, subways, and getting around"},order:3,icon:"Bus"},{id:"weather",level:"A2",title:{ko:"날씨",en:"Weather"},description:{ko:"날씨와 계절 말하기",en:"Talking about weather and seasons"},order:4,icon:"CloudSun"},{id:"hobby",level:"A2",title:{ko:"취미·여가",en:"Hobbies"},description:{ko:"취미와 여가 활동",en:"Hobbies and free-time activities"},order:5,icon:"Gamepad2"},{id:"work",level:"B1",title:{ko:"직장·업무",en:"Work"},description:{ko:"회의·보고·협업 표현",en:"Meetings, reports, and teamwork"},order:1,icon:"Briefcase"},{id:"health",level:"B1",title:{ko:"건강·병원",en:"Health"},description:{ko:"증상 설명·진료·약국",en:"Symptoms, doctors, and pharmacies"},order:2,icon:"Stethoscope"},{id:"travel",level:"B1",title:{ko:"여행",en:"Travel"},description:{ko:"예약·길찾기·문제 해결",en:"Booking, directions, and problem-solving"},order:3,icon:"Plane"},{id:"feelings",level:"B1",title:{ko:"감정·기분",en:"Feelings"},description:{ko:"기분·감정·공감 표현",en:"Moods, emotions, and empathy"},order:4,icon:"Smile"},{id:"appointment",level:"B1",title:{ko:"약속·일정",en:"Plans & Appointments"},description:{ko:"약속 잡기·변경·확인",en:"Making, changing, and confirming plans"},order:5,icon:"CalendarClock"},{id:"opinion",level:"B2",title:{ko:"의견·토론",en:"Opinions & Discussion"},description:{ko:"주장·반박·동의·근거 제시",en:"Stating, supporting, and challenging views"},order:1,icon:"MessagesSquare"},{id:"news",level:"B2",title:{ko:"뉴스·시사",en:"News & Current Affairs"},description:{ko:"보도·정책·여론·논란",en:"Reporting, policy, and public debate"},order:2,icon:"Newspaper"},{id:"environment",level:"B2",title:{ko:"환경",en:"Environment"},description:{ko:"기후·오염·지속가능성",en:"Climate, pollution, and sustainability"},order:3,icon:"Leaf"},{id:"technology",level:"B2",title:{ko:"기술·디지털",en:"Technology"},description:{ko:"인공지능·데이터·온라인 생활",en:"AI, data, and digital life"},order:4,icon:"Cpu"},{id:"culture",level:"B2",title:{ko:"문화·예술",en:"Culture & Arts"},description:{ko:"전통·대중문화·전시·공연",en:"Tradition, pop culture, and the arts"},order:5,icon:"Palette"},{id:"business",level:"C1",title:{ko:"비즈니스·회의",en:"Business"},description:{ko:"협상·보고·의사결정 표현",en:"Negotiation, reporting, and decision-making"},order:1,icon:"Briefcase"},{id:"society",level:"C1",title:{ko:"사회 이슈",en:"Social Issues"},description:{ko:"정책·격차·세대 담론",en:"Policy, inequality, and generational debate"},order:2,icon:"Landmark"},{id:"abstract",level:"C1",title:{ko:"추상적 사고·논리",en:"Abstract Thinking"},description:{ko:"전제·근거·반론의 논리 구조",en:"Premises, evidence, and counterarguments"},order:3,icon:"Brain"},{id:"media",level:"C1",title:{ko:"미디어·여론",en:"Media"},description:{ko:"보도·여론·프레임 분석",en:"Coverage, public opinion, and framing"},order:4,icon:"Newspaper"},{id:"academic",level:"C2",title:{ko:"전문·학술",en:"Academic"},description:{ko:"논문·발표·토론의 학술 어휘",en:"Scholarly vocabulary for papers, talks, and debate"},order:1,icon:"GraduationCap"},{id:"idioms",level:"C2",title:{ko:"관용 표현·속담",en:"Idioms & Proverbs"},description:{ko:"사자성어와 토박이 속담",en:"Four-character idioms and native proverbs"},order:2,icon:"BookMarked"},{id:"nuance",level:"C2",title:{ko:"미묘한 뉘앙스",en:"Subtle Nuance"},description:{ko:"비슷하지만 어감이 다른 표현",en:"Near-synonyms with subtly different shades"},order:3,icon:"Sparkles"},{id:"formal",level:"C2",title:{ko:"격식·연설",en:"Formal Speech"},description:{ko:"연설·문어체·공식 격식 표현",en:"Oratory, literary register, and official formality"},order:4,icon:"Megaphone"}],"SEED_VERSION_KO",0,3],830223)}]);